INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('11ddbf82-7556-454f-91aa-db1e76728d4d', '1d77b252-803d-494e-bfad-88987cc41eba', 'qcm', 'Dans "Aminata mange du riz", quel est le sujet ?', '{"bonne":2,"choix":["mange","du riz","Aminata","riz"],"explication":"\"Aminata\" est le sujet : c''est elle qui fait l''action de manger."}', 'Aminata', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('2f4e8ab1-3d46-4c73-976d-aecd5a4561b2', '1d77b252-803d-494e-bfad-88987cc41eba', 'qcm', 'Comment trouver le sujet d''un verbe ?', '{"bonne":1,"choix":["On cherche ce qui est après le verbe","On pose la question \"Qui ?\" ou \"Qu''est-ce qui ?\" avant le verbe","On cherche le plus long mot","On cherche le nom propre"],"explication":"Pour trouver le sujet, on pose la question \"Qui est-ce qui... ?\" avant le verbe."}', 'On pose la question "Qui ?" ou "Qu''est-ce qui ?" avant le verbe', 15) ON CONFLICT (id) DO NOTHING;
