INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('204adeb8-1508-4b56-8a8e-e7d0d6816c76', '28504243-d30d-494f-8004-b3523fc293fc', 'qcm', 'Quelle phrase est déclarative (affirme quelque chose) ?', '{"bonne":2,"choix":["Viens !","Viens-tu ?","Tu viens.","Comme tu viens vite !"],"explication":"La phrase déclarative déclare un fait. Elle se termine par un point."}', 'Tu viens.', 10) ON CONFLICT (id) DO NOTHING;
