INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('8431bdae-5c24-49b7-8139-e956c71e7897', '2a38fed0-0bae-4f35-beb7-e0b60e856ab5', 'qcm', 'Convertis 3 L 50 cL en cL', '{"bonne":0,"choix":["350 cL","3 050 cL","305 cL","3 500 cL"],"explication":"3 L = 300 cL, 300 + 50 = 350 cL"}', '350 cL', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('9fe57c5f-2983-4318-b262-076763aae02b', '2a38fed0-0bae-4f35-beb7-e0b60e856ab5', 'qcm', 'Un bidon contient 5 L de jus. On sert 3 L 25 cL. Combien reste-t-il ?', '{"bonne":1,"choix":["1 L 50 cL","1 L 75 cL","2 L 25 cL","1 L 25 cL"],"explication":"5 L = 500 cL, 500 - 325 = 175 cL = 1 L 75 cL"}', '1 L 75 cL', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('b90e9471-0c43-4bdf-a89f-8600ca910835', '2a38fed0-0bae-4f35-beb7-e0b60e856ab5', 'qcm', 'Un seau contient 12 L. Un autre contient 8 L. Quelle est la différence ?', '{"bonne":1,"choix":["2 L","4 L","6 L","8 L"],"explication":"12 L - 8 L = 4 L"}', '4 L', 10) ON CONFLICT (id) DO NOTHING;
