INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('efc41c2c-1954-4675-99b4-c533b4adc7e7', '2a38fed0-0bae-4f35-beb7-e0b60e856ab5', 'qcm', 'Aminata boit 3 verres de 20 cL par jour. Combien de cL boit-elle en 5 jours ?', '{"bonne":2,"choix":["200 cL","250 cL","300 cL","350 cL"],"explication":"3 × 20 = 60 cL par jour, 60 × 5 = 300 cL en 5 jours"}', '300 cL', 15) ON CONFLICT (id) DO NOTHING;
