INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('2bde8224-42ce-46f9-806a-341ea9746913', '2afe6c86-b556-41c8-8968-59d633eb6a59', 'qcm', 'Quel service public fournit l eau potable aux habitations ?', '{"bonne":1,"choix":["La CNPS","La SODECI","La SOTRA","La CIE"],"explication":"La SODECI (Societe de Distribution d Eau de CI) fournit l eau potable en CI."}', 'La SODECI', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('6b9f5ec1-1c88-403b-85e4-6ca2f959012b', '2afe6c86-b556-41c8-8968-59d633eb6a59', 'qcm', 'Pourquoi ne faut-il pas bloquer les caniveaux avec des dechets ?', '{"bonne":1,"choix":["Pour ne pas salir les caniveaux","Parce que les caniveaux bouches causent des inondations","Parce que c est interdit seulement","Parce que ca gene la circulation"],"explication":"Les caniveaux bloques ne permettent plus l evacuation des eaux de pluie, causant des inondations."}', 'Parce que les caniveaux bouches causent des inondations', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('7a562a0c-27c2-47a0-92f4-4f38d39862e8', '2afe6c86-b556-41c8-8968-59d633eb6a59', 'qcm', 'Qui dirige une commune en Cote d Ivoire ?', '{"bonne":2,"choix":["Un prefet","Un gouverneur","Un maire","Un ministre"],"explication":"Le maire est le premier magistrat d une commune, elu par les habitants."}', 'Un maire', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('8eaa6707-d999-421a-86a8-02cfda0f0e1e', '2afe6c86-b556-41c8-8968-59d633eb6a59', 'qcm', 'Qu est-ce que le civisme au quotidien dans le quartier ?', '{"bonne":1,"choix":["Faire tout ce qu on veut","Respecter les regles de vie commune : saluer, ne pas faire de bruit excessif, respecter les biens communs","Ignorer les voisins","N avoir aucune obligation"],"explication":"Le civisme c est respecter les regles de vie commune pour un quartier agreable pour tous."}', 'Respecter les regles de vie commune : saluer, ne pas faire de bruit excessif, respecter les biens communs', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a8b25f14-91b0-41d9-a7f2-4ad21e793872', '2afe6c86-b556-41c8-8968-59d633eb6a59', 'qcm', 'Qu est-ce que la solidarite dans un quartier ?', '{"bonne":1,"choix":["Faire des fetes tous les jours","S entraider, se soutenir mutuellement dans les moments difficiles","Surveiller les voisins","Partager les memes opinions"],"explication":"La solidarite est l aide mutuelle entre voisins, notamment dans les moments difficiles."}', 'S entraider, se soutenir mutuellement dans les moments difficiles', 10) ON CONFLICT (id) DO NOTHING;
