INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d8189061-677a-4f17-8df0-9ba46f48fbbf', '2afe6c86-b556-41c8-8968-59d633eb6a59', 'qcm', 'Qu est-ce qu un quartier ?', '{"bonne":1,"choix":["Une grande ville","Une division d une ville ou d un village","Un departement","Un pays"],"explication":"Un quartier est une subdivision d une ville, groupe de rues formant une unite."}', 'Une division d une ville ou d un village', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0578a5d4-d895-4354-adbc-15f46131c9a6', '32ae6151-9cb6-4187-9d4d-adf0c378d5f0', 'qcm', 'Qu est-ce que la democratie ?', '{"bonne":1,"choix":["Le gouvernement d une seule personne","Le systeme ou le pouvoir appartient au peuple","Un type de dictature","Le gouvernement des militaires"],"explication":"La democratie est le systeme politique ou le peuple est souverain et exerce le pouvoir."}', 'Le systeme ou le pouvoir appartient au peuple', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('129bdc0e-78b1-4bcd-bead-d102a6cd0c46', '32ae6151-9cb6-4187-9d4d-adf0c378d5f0', 'qcm', 'Qu est-ce que le suffrage universel ?', '{"bonne":1,"choix":["Le vote reserve aux riches","Le droit de vote accorde a tous les citoyens adultes sans distinction","Le vote des seuls hommes","Le vote des seuls diplomes"],"explication":"Le suffrage universel signifie que tous les citoyens adultes (18+) ont le droit de voter."}', 'Le droit de vote accorde a tous les citoyens adultes sans distinction', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('22556479-08ac-47a9-8cbd-8073f4d9c158', '32ae6151-9cb6-4187-9d4d-adf0c378d5f0', 'qcm', 'Qu est-ce que la fraude electorale ?', '{"bonne":1,"choix":["Un vote valide","Des actes illegaux pour fausser les resultats d une election","Un recomptage de votes","Un bulletin de vote normal"],"explication":"La fraude electorale comprend la tromperie, la corruption ou la falsification pour voler une election."}', 'Des actes illegaux pour fausser les resultats d une election', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('79701b2b-0499-458c-98be-1148efa4cc30', '32ae6151-9cb6-4187-9d4d-adf0c378d5f0', 'qcm', 'Comment peut-on participer a la vie democratique meme sans voter (pour les enfants) ?', '{"bonne":1,"choix":["On ne peut pas","En suivant l actualite, en discutant avec les adultes, en s engageant dans la vie scolaire et communautaire","En ignorant la politique","En faisant du sport"],"explication":"Les enfants participent a la democratie par l engagement scolaire, culturel et associatif."}', 'En suivant l actualite, en discutant avec les adultes, en s engageant dans la vie scolaire et communautaire', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('7e3fe731-a0ec-4ca5-b7e8-ef456b21299c', '32ae6151-9cb6-4187-9d4d-adf0c378d5f0', 'qcm', 'Qu est-ce qu une Constitution ?', '{"bonne":1,"choix":["Un reglement scolaire","La loi fondamentale qui organise le pouvoir dans un Etat","Un accord commercial","Un traite international"],"explication":"La Constitution est la loi suprème qui definit les règles d organisation du pouvoir dans un pays."}', 'La loi fondamentale qui organise le pouvoir dans un Etat', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('868851cf-5338-4acb-8e4e-58fe1737d519', '32ae6151-9cb6-4187-9d4d-adf0c378d5f0', 'qcm', 'Qu est-ce qu un parti politique ?', '{"bonne":1,"choix":["Une fete organisee par des hommes politiques","Un groupe de personnes partageant des idees pour gouverner le pays","Un tribunal politique","Un syndicat de travailleurs"],"explication":"Un parti politique regroupe des personnes avec un programme et des idees communes pour gouverner."}', 'Un groupe de personnes partageant des idees pour gouverner le pays', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('9d6862c0-9d6a-4759-a023-c1442e848864', '32ae6151-9cb6-4187-9d4d-adf0c378d5f0', 'qcm', 'Qu est-ce que l abstention lors d une election ?', '{"bonne":1,"choix":["Voter blanc","Ne pas aller voter alors qu on en a le droit","Annuler son vote","Voter deux fois"],"explication":"L abstention c est la non-participation a un vote. Elle reduit la legitimite democratique."}', 'Ne pas aller voter alors qu on en a le droit', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('aff86968-e187-4a0b-9203-1741b883daa5', '32ae6151-9cb6-4187-9d4d-adf0c378d5f0', 'qcm', 'Quel organisme organise les elections en CI ?', '{"bonne":1,"choix":["La police","Le CEI (Commission Electorale Independante)","Le tribunal","Les partis politiques"],"explication":"La CEI est l organisme independant charge d organiser et superviser les elections en CI."}', 'Le CEI (Commission Electorale Independante)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('b4011399-e49b-47c0-806b-e3c59290af04', '32ae6151-9cb6-4187-9d4d-adf0c378d5f0', 'qcm', 'Qu est-ce qu une election ?', '{"bonne":1,"choix":["Une fete nationale","Un processus par lequel les citoyens choisissent leurs representants","Un concours scolaire","Un tribunal"],"explication":"Une election est un processus democratique permettant aux citoyens de choisir leurs dirigeants."}', 'Un processus par lequel les citoyens choisissent leurs representants', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f65090da-5b43-4697-8d75-e4e3e5d23456', '32ae6151-9cb6-4187-9d4d-adf0c378d5f0', 'qcm', 'Pourquoi voter est-il important ?', '{"bonne":1,"choix":["Pour recevoir de l argent","Parce que c est la maniere dont les citoyens choisissent leurs dirigeants","Parce qu on y est force","Ce n est pas important"],"explication":"Voter est le moyen pour chaque citoyen de participer aux decisions de son pays."}', 'Parce que c est la maniere dont les citoyens choisissent leurs dirigeants', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0dedfe8f-8aea-4e3d-8418-ff6589be41dd', '350e851c-5a40-496d-84cb-30f2da0cb641', 'qcm', 'Conjugue "avoir" au futur avec "nous" :', '{"bonne":1,"choix":["nous avons","nous aurons","nous aurions","nous avions"],"explication":"Nous aurons (futur irrégulier d''\"avoir\")"}', 'nous aurons', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('195b5e50-b0ef-4eaa-b797-8237b2432af7', '350e851c-5a40-496d-84cb-30f2da0cb641', 'qcm', 'Conjugue "faire" au futur avec "ils" :', '{"bonne":0,"choix":["ils feront","ils faisaient","ils feraient","ils font"],"explication":"Ils feront (futur irrégulier de \"faire\" : fer-)"}', 'ils feront', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('290d0862-8e19-4f05-b34f-85589c1238cb', '350e851c-5a40-496d-84cb-30f2da0cb641', 'qcm', 'Conjugue "aller" au futur avec "vous" :', '{"bonne":1,"choix":["vous allez","vous irez","vous iriez","vous allerez"],"explication":"Vous irez (futur irrégulier d''\"aller\" : ir-)"}', 'vous irez', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('43f077f5-84f1-4d92-b979-c9341b777f96', '350e851c-5a40-496d-84cb-30f2da0cb641', 'qcm', 'Conjugue "chanter" au futur avec "je" :', '{"bonne":0,"choix":["je chanterai","je chanterais","je chantais","je chanterez"],"explication":"Je chanterai (futur 1er groupe = infinitif + -ai)"}', 'je chanterai', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('44e84698-32cb-4946-9035-1cfff91e23db', '350e851c-5a40-496d-84cb-30f2da0cb641', 'qcm', 'Quelle phrase est au futur simple ?', '{"bonne":3,"choix":["Je mange.","J''ai mangé.","Je mangeais.","Je mangerai."],"explication":"\"Je mangerai\" est au futur simple."}', 'Je mangerai.', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('59b36989-50de-427b-93a0-d088fe039453', '350e851c-5a40-496d-84cb-30f2da0cb641', 'qcm', 'Conjugue "venir" au futur avec "elle" :', '{"bonne":1,"choix":["elle vient","elle viendra","elle venait","elle serait venue"],"explication":"Elle viendra (futur irrégulier de \"venir\" : viendr-)"}', 'elle viendra', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('5a217a8e-750c-4836-887a-87cc5c501c57', '350e851c-5a40-496d-84cb-30f2da0cb641', 'qcm', 'Conjugue "finir" au futur avec "tu" :', '{"bonne":0,"choix":["tu finiras","tu finirais","tu finissais","tu finirez"],"explication":"Tu finiras (futur 2e groupe = infinitif + -as)"}', 'tu finiras', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('8cd85cbe-236c-41e4-89b6-dea2a0f1c1af', '350e851c-5a40-496d-84cb-30f2da0cb641', 'qcm', 'Transforme au futur : "Il mange." →', '{"bonne":2,"choix":["Il mangeait.","Il a mangé.","Il mangera.","Il mangerait."],"explication":"\"Il mangera\" est le futur de \"il mange\""}', 'Il mangera.', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ae7b68bd-00c3-466e-83eb-40d2f497734f', '350e851c-5a40-496d-84cb-30f2da0cb641', 'qcm', 'Conjugue "être" au futur avec "il" :', '{"bonne":0,"choix":["il sera","il serait","il étais","il seras"],"explication":"Il sera (futur irrégulier d''\"être\")"}', 'il sera', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d9101253-287a-4ba6-b70f-33d900e0e2ef', '350e851c-5a40-496d-84cb-30f2da0cb641', 'qcm', 'Quelle terminaison indique le futur à la 2e pers. du pluriel ?', '{"bonne":1,"choix":["-ez","-rez","-iez","-erez"],"explication":"Au futur : vous chanter-ez, vous partir-ez... terminaison : -rez"}', '-rez', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0cce2144-177a-4754-833b-b80bd9e2e5d6', '357704a8-3d3e-47af-aee9-9fce100c9158', 'qcm', 'Quelle est le quotient de 63 ÷ 7 ?', '{"bonne":2,"choix":["7","8","9","6"],"explication":"63 ÷ 7 = 9"}', '9', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('20603264-d922-4c07-b2fa-0ee469640a80', '357704a8-3d3e-47af-aee9-9fce100c9158', 'qcm', 'On divise 50 par 4. Quel est le reste ?', '{"bonne":2,"choix":["0","1","2","3"],"explication":"50 = 4 × 12 + 2, le reste est 2"}', '2', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('34eadfdc-7937-44fb-b9f4-b09864ca4a84', '357704a8-3d3e-47af-aee9-9fce100c9158', 'qcm', 'Combien font 96 ÷ 8 ?', '{"bonne":2,"choix":["10","11","12","13"],"explication":"96 ÷ 8 = 12 car 8 × 12 = 96"}', '12', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('559cd204-6209-431a-9073-2234b6ffed4e', '357704a8-3d3e-47af-aee9-9fce100c9158', 'qcm', 'Combien font 45 ÷ 9 ?', '{"bonne":1,"choix":["4","5","6","7"],"explication":"45 ÷ 9 = 5 car 9 × 5 = 45"}', '5', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('66a3616c-5188-48b3-adec-c5175aabb069', '357704a8-3d3e-47af-aee9-9fce100c9158', 'qcm', 'On répartit 84 stylos en paquets de 6. Combien de paquets ?', '{"bonne":2,"choix":["12","13","14","15"],"explication":"84 ÷ 6 = 14 paquets"}', '14', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('7a4efa1f-5158-4bf5-987f-33b1fbc1d95e', '357704a8-3d3e-47af-aee9-9fce100c9158', 'qcm', 'Quel est le quotient de 77 ÷ 7 ?', '{"bonne":2,"choix":["9","10","11","12"],"explication":"77 ÷ 7 = 11"}', '11', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a3ad7fe0-5363-41e5-b98d-1bb791541f28', '357704a8-3d3e-47af-aee9-9fce100c9158', 'qcm', 'On doit ranger 85 livres dans des boîtes de 10. Combien de boîtes complètes et combien de livres restants ?', '{"bonne":1,"choix":["7 boîtes, 15 restants","8 boîtes, 5 restants","9 boîtes, 4 restants","8 boîtes, 15 restants"],"explication":"85 = 10 × 8 + 5, soit 8 boîtes complètes et 5 livres restants"}', '8 boîtes, 5 restants', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e645964e-e2c0-4298-a84f-675bbe22f298', '357704a8-3d3e-47af-aee9-9fce100c9158', 'qcm', 'Combien font 108 ÷ 9 ?', '{"bonne":2,"choix":["10","11","12","13"],"explication":"108 ÷ 9 = 12 car 9 × 12 = 108"}', '12', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f2e856cb-94cd-4202-8a9b-6d42f6b19db2', '357704a8-3d3e-47af-aee9-9fce100c9158', 'qcm', 'Combien font 72 ÷ 8 ?', '{"bonne":2,"choix":["7","8","9","6"],"explication":"72 ÷ 8 = 9 car 8 × 9 = 72"}', '9', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f549a4f1-bee1-4fc6-98a7-269d7d1bf86c', '357704a8-3d3e-47af-aee9-9fce100c9158', 'qcm', 'On partage 100 biscuits entre 7 enfants. Combien chacun reçoit-il et quel est le reste ?', '{"bonne":1,"choix":["13 et reste 9","14 et reste 2","14 et reste 4","15 et reste 1"],"explication":"100 = 7 × 14 + 2, donc 14 biscuits chacun et reste 2"}', '14 et reste 2', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('00a461f3-6173-4dc3-908a-597131cf504b', '367e7de2-76f6-4365-ac0c-3938c4a6cf75', 'qcm', 'Quelle est la principale loi de la CI ?', '{"bonne":2,"choix":["Le code civil","Le code penal","La Constitution","Le reglement"],"explication":"La Constitution est la loi supreme de la Cote d Ivoire."}', 'La Constitution', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('3afc56ce-0026-434f-9384-a8a508464717', '367e7de2-76f6-4365-ac0c-3938c4a6cf75', 'qcm', 'Quel droit garantit la liberte de s exprimer ?', '{"bonne":1,"choix":["Le droit a l education","La liberte d expression","Le droit de vote","La liberte de circulation"],"explication":"La liberte d expression est le droit de pouvoir exprimer ses opinions librement."}', 'La liberte d expression', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('42203cb2-cd31-454d-a1ce-f4d55396f7cf', '367e7de2-76f6-4365-ac0c-3938c4a6cf75', 'qcm', 'Qu est-ce que l etat de droit ?', '{"bonne":1,"choix":["Un pays ou les lois ne s appliquent qu aux pauvres","Un pays ou tout le monde, y compris le gouvernement, est soumis a la loi","Un pays dirigé par des avocats","Un pays avec beaucoup de tribunaux"],"explication":"L etat de droit signifie que la loi s applique a tous egalement, meme au gouvernement."}', 'Un pays ou tout le monde, y compris le gouvernement, est soumis a la loi', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('43db416b-25f7-440a-a3cd-6aac1362e144', '367e7de2-76f6-4365-ac0c-3938c4a6cf75', 'qcm', 'Qu est-ce que la DUDH ?', '{"bonne":1,"choix":["Un document de la CI","La Declaration Universelle des Droits de l Homme (ONU 1948)","Un traite militaire","Un accord commercial"],"explication":"La DUDH adoptee par l ONU en 1948 proclame les droits fondamentaux de tous les etres humains."}', 'La Declaration Universelle des Droits de l Homme (ONU 1948)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('4c9c829a-600b-415b-b046-177bec252383', '367e7de2-76f6-4365-ac0c-3938c4a6cf75', 'qcm', 'Qu est-ce qu un citoyen ?', '{"bonne":1,"choix":["Toute personne qui habite dans un pays","Une personne ayant la nationalite d un pays avec des droits et devoirs","Un fonctionnaire de l Etat","Un habitant d une ville"],"explication":"Un citoyen est une personne reconnue par un Etat, jouissant de droits et soumise a des devoirs."}', 'Une personne ayant la nationalite d un pays avec des droits et devoirs', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('4f4f78aa-38e0-48c6-a9da-f62f9af06e9f', '367e7de2-76f6-4365-ac0c-3938c4a6cf75', 'qcm', 'A partir de quel age peut-on voter en CI ?', '{"bonne":1,"choix":["16 ans","18 ans","21 ans","25 ans"],"explication":"En Cote d Ivoire, le droit de vote est accorde aux citoyens ayant 18 ans ou plus."}', '18 ans', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('89cd1a4b-48e6-40e7-97b7-ab52c351e9b9', '367e7de2-76f6-4365-ac0c-3938c4a6cf75', 'qcm', 'Que signifie la devise de la CI "Union-Discipline-Travail" ?', '{"bonne":1,"choix":["Ce sont les noms des 3 presidents","Ce sont les valeurs fondamentales de la nation ivoirienne","Ce sont les 3 regions principales","Ce sont les 3 langues principales"],"explication":"La devise de la CI appelle les citoyens a l unite, a la discipline et au travail pour le developpement."}', 'Ce sont les valeurs fondamentales de la nation ivoirienne', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('9da38389-2c48-4b42-8b08-464c07ea0676', '367e7de2-76f6-4365-ac0c-3938c4a6cf75', 'qcm', 'Qu est-ce qu un droit fondamental ?', '{"bonne":1,"choix":["Un droit qu on peut acheter","Un droit que tout etre humain possede du fait de sa naissance","Un privilege accorde par le gouvernement","Un droit des adultes seulement"],"explication":"Les droits fondamentaux sont des droits inaliénables appartenant a tout etre humain."}', 'Un droit que tout etre humain possede du fait de sa naissance', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c0e32efd-f55b-480a-aac9-906ca0e6727e', '367e7de2-76f6-4365-ac0c-3938c4a6cf75', 'qcm', 'Quel est le devoir de chaque citoyen ivoirien ?', '{"bonne":1,"choix":["Travailler pour un ministre","Respecter les lois, payer les impots, servir la nation","Partir a l etranger","Voter pour le president en place"],"explication":"Les citoyens ont le devoir de respecter les lois, payer les impots et contribuer a la nation."}', 'Respecter les lois, payer les impots, servir la nation', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('faeb5674-f5ff-4d48-95ce-c91540639397', '367e7de2-76f6-4365-ac0c-3938c4a6cf75', 'qcm', 'Quel organisme vote les lois en CI ?', '{"bonne":1,"choix":["Le president","L Assemblee nationale","Les ministres","Les tribunaux"],"explication":"L Assemblee nationale est constituee de deputes qui votent les lois en CI."}', 'L Assemblee nationale', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1328575b-5109-4840-ad34-36311df8ba48', '36a45794-3260-479d-bd25-6cbb61508180', 'qcm', 'En combien de temps la Terre fait-elle le tour du Soleil ?', '{"bonne":2,"choix":["1 mois","6 mois","1 an","10 ans"],"explication":"La Terre met 365 jours (1 an) pour faire le tour complet du Soleil."}', '1 an', 10) ON CONFLICT (id) DO NOTHING;
