INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('73a1927c-ec5a-4531-9504-afb2e1fa7671', '4dfd8ba9-25af-4ea6-b08e-3473a1adbc04', 'qcm', 'Comment calcule-t-on le périmètre d''un carré de côté 5 cm ?', '{"bonne":2,"choix":["5+5","5×2","5×4","5×5"],"explication":"Périmètre du carré = 4 × côté = 4 × 5 = 20 cm"}', '5×4', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('75e719d2-b59b-43ce-ab7c-bbc224835983', '4dfd8ba9-25af-4ea6-b08e-3473a1adbc04', 'qcm', 'Kofi fait 3 fois le tour d''un terrain carré de côté 20 m. Quelle distance parcourt-il ?', '{"bonne":2,"choix":["60 m","120 m","240 m","360 m"],"explication":"Périmètre = 4×20 = 80 m, 3 tours = 3×80 = 240 m"}', '240 m', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('861b3607-83fd-4d67-a3d9-2743f2026442', '4dfd8ba9-25af-4ea6-b08e-3473a1adbc04', 'qcm', 'Un jardin rectangulaire mesure 15 m de long et 10 m de large. Quelle longueur de clôture faut-il ?', '{"bonne":1,"choix":["25 m","50 m","75 m","150 m"],"explication":"P = 2 × (15 + 10) = 2 × 25 = 50 m"}', '50 m', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('bc0e14dc-fe85-4402-8023-5ca4109908ba', '4dfd8ba9-25af-4ea6-b08e-3473a1adbc04', 'qcm', 'Un triangle équilatéral a un périmètre de 27 cm. Quelle est la longueur d''un côté ?', '{"bonne":1,"choix":["7 cm","9 cm","11 cm","13 cm"],"explication":"Côté = 27 ÷ 3 = 9 cm (triangle équilatéral = 3 côtés égaux)"}', '9 cm', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('bdf6b05e-0c91-48ac-a46a-01b3dabad474', '4dfd8ba9-25af-4ea6-b08e-3473a1adbc04', 'qcm', 'Un carré a un périmètre de 32 cm. Quelle est la longueur de son côté ?', '{"bonne":1,"choix":["4 cm","8 cm","16 cm","32 cm"],"explication":"Côté = périmètre ÷ 4 = 32 ÷ 4 = 8 cm"}', '8 cm', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d51ba85a-8cbb-437d-8756-069ae33636e9', '4dfd8ba9-25af-4ea6-b08e-3473a1adbc04', 'qcm', 'Un rectangle a un périmètre de 40 cm et une longueur de 12 cm. Quelle est sa largeur ?', '{"bonne":1,"choix":["6 cm","8 cm","10 cm","28 cm"],"explication":"2(l+L)=40, l+L=20, L=12 donc l=20-12=8 cm"}', '8 cm', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d795ed02-61ef-44b5-b89d-09593f592eb0', '4dfd8ba9-25af-4ea6-b08e-3473a1adbc04', 'qcm', 'Quel est le périmètre d''un carré de côté 7 cm ?', '{"bonne":2,"choix":["14 cm","21 cm","28 cm","49 cm"],"explication":"P = 4 × 7 = 28 cm"}', '28 cm', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1645039d-4f67-4e8c-bcb7-8c24826bf418', '4ff3ec8c-b17a-4b6c-8fdf-d2e4fa9304a0', 'qcm', 'Qu est-ce que la maltraitance ?', '{"bonne":1,"choix":["Une recompense","Tout acte de violence physique, psychologique ou negligence envers un enfant","Une forme de jeu","Une methode d education"],"explication":"La maltraitance englobe la violence physique, les abus psychologiques et la negligence envers l enfant."}', 'Tout acte de violence physique, psychologique ou negligence envers un enfant', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('192865fe-a79c-49a9-8a51-496e66b30a0e', '4ff3ec8c-b17a-4b6c-8fdf-d2e4fa9304a0', 'qcm', 'Quel droit fondamental garantit a tout enfant d aller a l ecole ?', '{"bonne":1,"choix":["Le droit au jeu","Le droit a l education","Le droit au vote","Le droit a la propriete"],"explication":"Le droit a l education est un droit fondamental de tout enfant, reconnu mondialement."}', 'Le droit a l education', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('588c18e6-ef0b-4bd9-95f5-39a2e2f45177', '4ff3ec8c-b17a-4b6c-8fdf-d2e4fa9304a0', 'qcm', 'Qu est-ce que la CDE (Convention des droits de l enfant) ?', '{"bonne":1,"choix":["Un club pour enfants","Un traite international de l ONU protege les droits des enfants","Un jeu pedagogique","Une loi ivoirienne uniquement"],"explication":"La CDE (1989) est le traite le plus ratifie au monde, garantissant les droits des enfants."}', 'Un traite international de l ONU protege les droits des enfants', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('662a7c27-f332-4071-911b-df744b5def5f', '4ff3ec8c-b17a-4b6c-8fdf-d2e4fa9304a0', 'qcm', 'Qu est-ce que le travail des enfants ?', '{"bonne":2,"choix":["Les devoirs scolaires","Le travail domestique leger","Faire travailler des enfants de facon excessive en les privant d ecole et d enfance","Aider les parents a la maison raisonnablement"],"explication":"Le travail des enfants exploite les mineurs, les privant d education et de leur enfance."}', 'Faire travailler des enfants de facon excessive en les privant d ecole et d enfance', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('717751f9-5564-469d-9d3c-51a5b00caf78', '4ff3ec8c-b17a-4b6c-8fdf-d2e4fa9304a0', 'qcm', 'Quel age marque la fin de l enfance selon la CDE ?', '{"bonne":2,"choix":["15 ans","16 ans","18 ans","21 ans"],"explication":"La CDE definit l enfant comme toute personne de moins de 18 ans."}', '18 ans', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('83ef7165-b9c1-4e35-9ae4-7fc31eada37a', '4ff3ec8c-b17a-4b6c-8fdf-d2e4fa9304a0', 'qcm', 'Quel droit garantit qu un enfant soit avec sa famille ?', '{"bonne":1,"choix":["Le droit au jeu","Le droit a la famille et de ne pas en etre separe sans raison grave","Le droit au logement","Le droit a la sante"],"explication":"Tout enfant a le droit de vivre avec sa famille et d en recevoir soins et affection."}', 'Le droit a la famille et de ne pas en etre separe sans raison grave', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('8a0b71d0-2143-4865-a887-c1d30a330345', '4ff3ec8c-b17a-4b6c-8fdf-d2e4fa9304a0', 'qcm', 'Quel droit permet a un enfant de pratiquer sa religion ?', '{"bonne":1,"choix":["Le droit au jeu","La liberte de religion et de conscience","Le droit a l education","Le droit au logement"],"explication":"La liberte de religion garantit a tout enfant le droit de pratiquer (ou non) une religion."}', 'La liberte de religion et de conscience', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('9dc9b3db-e706-4575-9532-606ccc70fdcf', '4ff3ec8c-b17a-4b6c-8fdf-d2e4fa9304a0', 'qcm', 'Que faire si un enfant est victime de violence ?', '{"bonne":1,"choix":["Garder le secret","En parler a un adulte de confiance ou aux autorites","Se venger seul","Fuir le pays"],"explication":"Un enfant victime de violence doit en parler a un adulte de confiance (parent, maitre, police)."}', 'En parler a un adulte de confiance ou aux autorites', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('bb501af1-9a24-49ac-9885-575180ad56e1', '4ff3ec8c-b17a-4b6c-8fdf-d2e4fa9304a0', 'qcm', 'Qu est-ce que l UNICEF ?', '{"bonne":1,"choix":["Une ONG ivoirienne","Une agence de l ONU pour les droits et le bien-etre des enfants","Un programme scolaire","Une emission television"],"explication":"L UNICEF est le Fonds des Nations Unies pour l Enfance, qui defend les droits des enfants."}', 'Une agence de l ONU pour les droits et le bien-etre des enfants', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('bd9c7d49-b86a-4077-a99b-4e701adbf1a0', '4ff3ec8c-b17a-4b6c-8fdf-d2e4fa9304a0', 'qcm', 'Pourquoi est-il important de connaitre ses droits ?', '{"bonne":1,"choix":["Pour se vanter","Pour pouvoir les exercer et les defendre","Pour faire peur aux adultes","Ce n est pas utile"],"explication":"Connaitre ses droits permet de les exercer, de les defendre et de les respecter chez les autres."}', 'Pour pouvoir les exercer et les defendre', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('141b272b-b732-4028-8f4d-38ccbeae4e29', '5423f564-69ee-4948-877c-a8c8b086f0cd', 'qcm', 'Combien font 1 245 + 2 867 ?', '{"bonne":1,"choix":["4 012","4 112","3 112","4 102"],"explication":"1 245 + 2 867 = 4 112"}', '4 112', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('242e11a6-5e37-48dc-af4a-e1b40f04f3b9', '5423f564-69ee-4948-877c-a8c8b086f0cd', 'qcm', 'Aïcha a 1 350 F. Sa maman lui donne 875 F. Combien a-t-elle au total ?', '{"bonne":0,"choix":["2 125 F","2 225 F","2 215 F","2 025 F"],"explication":"1 350 + 875 = 2 225 F"}', '2 125 F', 15) ON CONFLICT (id) DO NOTHING;
