INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('5333402c-6400-48c1-92b0-bc792d7b0100', '5423f564-69ee-4948-877c-a8c8b086f0cd', 'qcm', 'Combien font 99 + 99 ?', '{"bonne":2,"choix":["188","189","198","197"],"explication":"99 + 99 = 198"}', '198', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('7f58f2b9-41f4-44bf-a054-62cc325fbc7d', '5423f564-69ee-4948-877c-a8c8b086f0cd', 'qcm', 'Combien font 708 + 595 ?', '{"bonne":1,"choix":["1 203","1 303","1 213","1 403"],"explication":"708 + 595 = 1 303"}', '1 303', 10) ON CONFLICT (id) DO NOTHING;
