INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d64429f1-24ad-4e4a-a67e-819e559e3b9a', '5423f564-69ee-4948-877c-a8c8b086f0cd', 'qcm', 'Kofi parcourt 1 264 m le matin et 978 m le soir. Quelle distance totale parcourt-il ?', '{"bonne":1,"choix":["2 142 m","2 242 m","2 342 m","2 042 m"],"explication":"1 264 + 978 = 2 242 m"}', '2 242 m', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d82b5350-9eef-4dd1-be8f-8037fe0361d2', '5423f564-69ee-4948-877c-a8c8b086f0cd', 'qcm', 'Combien font 999 + 1 ?', '{"bonne":0,"choix":["1 000","1 001","999","1 009"],"explication":"999 + 1 = 1 000"}', '1 000', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f056d961-1b5c-41f0-ace4-5acdc5f36c1a', '5423f564-69ee-4948-877c-a8c8b086f0cd', 'qcm', 'Dans un marché, on vend 485 oranges le matin et 637 l''après-midi. Combien d''oranges au total ?', '{"bonne":1,"choix":["1 012","1 122","1 022","1 222"],"explication":"485 + 637 = 1 122 oranges"}', '1 122', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1c1c2147-5e13-4df6-a3d1-046805806781', '5477de7a-638d-4663-8ee0-2ba0c3a7ba85', 'qcm', 'Combien de km y a-t-il dans 1 000 m ?', '{"bonne":1,"choix":["0,1 km","1 km","10 km","100 km"],"explication":"1 000 m = 1 km"}', '1 km', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('2561d514-0d16-46a3-9657-03b810648ea8', '5477de7a-638d-4663-8ee0-2ba0c3a7ba85', 'qcm', 'Quelle est l''unité la plus petite parmi : km, m, dm, cm, mm ?', '{"bonne":3,"choix":["km","m","cm","mm"],"explication":"mm (millimètre) est la plus petite unité"}', 'mm', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('28618f4d-a5ba-435b-b737-0fdaf876cb27', '5477de7a-638d-4663-8ee0-2ba0c3a7ba85', 'qcm', 'Convertis 3 m 45 cm en centimètres', '{"bonne":0,"choix":["345 cm","354 cm","3 045 cm","3 450 cm"],"explication":"3 m = 300 cm, 300 + 45 = 345 cm"}', '345 cm', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('3004575e-6119-4797-928e-dcc962a1930a', '5477de7a-638d-4663-8ee0-2ba0c3a7ba85', 'qcm', 'Un élève mesure 1 m 38 cm. Sa soeur mesure 1 m 25 cm. Quelle est la différence ?', '{"bonne":1,"choix":["3 cm","13 cm","23 cm","33 cm"],"explication":"138 cm - 125 cm = 13 cm"}', '13 cm', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('397fe1bd-5863-4c1d-ac42-de287ffee6bd', '5477de7a-638d-4663-8ee0-2ba0c3a7ba85', 'qcm', 'Convertis 450 cm en mètres', '{"bonne":1,"choix":["0,45 m","4,5 m","45 m","4 500 m"],"explication":"450 cm ÷ 100 = 4,5 m"}', '4,5 m', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('718f0610-93d9-4c27-a8df-60b4d8ff3312', '5477de7a-638d-4663-8ee0-2ba0c3a7ba85', 'qcm', 'Combien de mm y a-t-il dans 1 cm ?', '{"bonne":0,"choix":["10","100","1000","5"],"explication":"1 cm = 10 mm"}', '10', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('74d69869-f275-4248-8067-85f6ca26879e', '5477de7a-638d-4663-8ee0-2ba0c3a7ba85', 'qcm', 'Un crayon mesure 17 cm 5 mm. Quelle est sa longueur en mm ?', '{"bonne":0,"choix":["175 mm","1 705 mm","170,5 mm","17,5 mm"],"explication":"17 cm = 170 mm, 170 + 5 = 175 mm"}', '175 mm', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('aa1d8d61-d14f-4fb8-ad6d-6d56549b082b', '5477de7a-638d-4663-8ee0-2ba0c3a7ba85', 'qcm', 'La longueur d''un terrain est 85 m. Sa largeur est 50 m. Quelle est la plus grande dimension ?', '{"bonne":1,"choix":["La largeur","La longueur","Elles sont égales","Impossible à dire"],"explication":"85 m > 50 m, donc la longueur est plus grande"}', 'La longueur', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('be5240df-00e0-4a9b-b049-978f688da01e', '5477de7a-638d-4663-8ee0-2ba0c3a7ba85', 'qcm', 'Combien de cm y a-t-il dans 1 m ?', '{"bonne":1,"choix":["10","100","1000","50"],"explication":"1 m = 100 cm"}', '100', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c07d4948-512d-4cc7-aedc-9c8226a92649', '5477de7a-638d-4663-8ee0-2ba0c3a7ba85', 'qcm', 'Convertis 2 km 500 m en mètres', '{"bonne":1,"choix":["250 m","2 500 m","25 000 m","205 m"],"explication":"2 km = 2 000 m, 2 000 + 500 = 2 500 m"}', '2 500 m', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('00f1f309-6fbf-4fa9-9d0a-11ececf7655c', '54ebb1a0-fc30-43d2-b629-6eca6e0765b0', 'qcm', 'Qu est-ce qu une plante annuelle ?', '{"bonne":0,"choix":["Une plante qui vit un an","Une plante qui vit deux ans","Une plante qui vit plusieurs annees","Une plante tropicale"],"explication":"Une plante annuelle accomplit son cycle de vie en un an."}', 'Une plante qui vit un an', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('040a8444-349e-45bc-8792-7794f0233972', '54ebb1a0-fc30-43d2-b629-6eca6e0765b0', 'qcm', 'Comment s appelle la graine du palmier ?', '{"bonne":1,"choix":["La noix de coco","La noix de palme","La datte","Le fruit a pain"],"explication":"Le palmier a huile produit la noix de palme."}', 'La noix de palme', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('16cf5b81-26f0-4192-b84f-32eebf5c484d', '54ebb1a0-fc30-43d2-b629-6eca6e0765b0', 'qcm', 'Qu est-ce que la pollinisation ?', '{"bonne":1,"choix":["La plantation des graines","Le transfert du pollen pour la reproduction","L arrosage des fleurs","La chute des feuilles"],"explication":"La pollinisation est le transport du pollen d une fleur a une autre pour la reproduction."}', 'Le transfert du pollen pour la reproduction', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('294fa5f8-a2f9-4061-8f2b-d81c0fcfcf13', '54ebb1a0-fc30-43d2-b629-6eca6e0765b0', 'qcm', 'Que produit une plante lors de la photosynthese ?', '{"bonne":1,"choix":["Du CO2","De l oxygene et du glucose","De l eau","De l azote"],"explication":"La photosynthese produit de l oxygene et du glucose (sucre) a partir du CO2 et de la lumiere."}', 'De l oxygene et du glucose', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('301a39bc-c56e-4a72-90ca-f5cd39c7fc74', '54ebb1a0-fc30-43d2-b629-6eca6e0765b0', 'qcm', 'Quel arbre est le plus commun en Cote d Ivoire ?', '{"bonne":1,"choix":["Le chene","Le palmier","Le sapin","Le bouleau"],"explication":"Le palmier est tres repandu en Cote d Ivoire, notamment le palmier a huile."}', 'Le palmier', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('4e01130c-9d60-4e00-89b0-211c0427ad8a', '54ebb1a0-fc30-43d2-b629-6eca6e0765b0', 'qcm', 'Quel est le role de la feuille dans la plante ?', '{"bonne":1,"choix":["Absorber l eau","Fabriquer la nourriture grace au soleil","Porter les fleurs","Stocker les reserves"],"explication":"La feuille realise la photosynthese pour fabriquer la nourriture de la plante."}', 'Fabriquer la nourriture grace au soleil', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('6847a9c6-e50f-4d4c-a5a8-6454467c58c1', '54ebb1a0-fc30-43d2-b629-6eca6e0765b0', 'qcm', 'Comment s appelle la partie de la plante qui absorbe l eau et les sels mineraux ?', '{"bonne":2,"choix":["La feuille","La tige","La racine","La fleur"],"explication":"Les racines absorbent l eau et les sels mineraux du sol."}', 'La racine', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('6d7d812c-4129-40db-8e65-f0b12756d490', '54ebb1a0-fc30-43d2-b629-6eca6e0765b0', 'qcm', 'Quel animal aide souvent a la pollinisation ?', '{"bonne":1,"choix":["Le lion","L abeille","Le crocodile","Le serpent"],"explication":"L abeille transporte le pollen de fleur en fleur en cherchant le nectar."}', 'L abeille', 10) ON CONFLICT (id) DO NOTHING;
