INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1d0b3ac4-8413-4b4e-ae1a-d276a94d8de8', '555e760c-ece8-4bc6-9cc6-4fa0e4b4dd68', 'qcm', 'Un champignon est-il une plante ?', '{"bonne":2,"choix":["Oui","Non, c est un animal","Non, c est un champignon, un regne a part","Oui, c est une plante sans fleur"],"explication":"Les champignons forment un regne a part, distinct des plantes et des animaux."}', 'Non, c est un champignon, un regne a part', 10) ON CONFLICT (id) DO NOTHING;
