INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('211c74b2-064b-46bc-8512-af946c727f3c', '564de187-8c00-432b-96dd-43e2da552f50', 'qcm', 'Que faire quand il y a un conflit dans la famille ?', '{"bonne":2,"choix":["Se battre","S en aller","En parler calmement et chercher une solution","Ne rien dire"],"explication":"Les conflits familiaux se resolvent par le dialogue calme et la recherche de solutions communes."}', 'En parler calmement et chercher une solution', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('30b5d97d-d9dc-4902-8176-e276c1bd8a4a', '564de187-8c00-432b-96dd-43e2da552f50', 'qcm', 'Pourquoi la famille est-elle importante ?', '{"bonne":1,"choix":["Pour avoir beaucoup d argent","Parce qu elle transmet les valeurs et protege ses membres","Pour avoir du pouvoir","Ce n est pas important"],"explication":"La famille est la premiere cellule sociale qui transmet les valeurs et protege chaque membre."}', 'Parce qu elle transmet les valeurs et protege ses membres', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('3202416e-a4f3-41c2-aaf0-a4c69f784511', '564de187-8c00-432b-96dd-43e2da552f50', 'qcm', 'Comment s appelle le frere de ton pere ou de ta mere ?', '{"bonne":2,"choix":["Ton cousin","Ton grand-pere","Ton oncle","Ton parrain"],"explication":"Le frere de ton pere ou de ta mere est ton oncle."}', 'Ton oncle', 10) ON CONFLICT (id) DO NOTHING;
