INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('642108eb-3638-443c-a1ae-4ff6fa1c552a', '564de187-8c00-432b-96dd-43e2da552f50', 'qcm', 'Qu est-ce que le respect des anciens dans la culture africaine ?', '{"bonne":1,"choix":["Avoir peur des vieux","Reconnaitre leur sagesse et leur experience en les traitant avec respect","Les eviter","Leur donner de l argent"],"explication":"En culture africaine, les anciens (grands-parents) sont honores pour leur sagesse et experience."}', 'Reconnaitre leur sagesse et leur experience en les traitant avec respect', 10) ON CONFLICT (id) DO NOTHING;
