INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a7c2adb6-5090-410d-8e94-2d1685798c3f', '564de187-8c00-432b-96dd-43e2da552f50', 'qcm', 'Comment s appelle la soeur de ton pere ou de ta mere ?', '{"bonne":2,"choix":["Ta cousine","Ta grand-mere","Ta tante","Ta marraine"],"explication":"La soeur de ton pere ou de ta mere est ta tante."}', 'Ta tante', 10) ON CONFLICT (id) DO NOTHING;
