INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e6c61411-2f52-4dab-bd61-eec0c592204b', '564de187-8c00-432b-96dd-43e2da552f50', 'qcm', 'Qu est-ce qu une famille elargie ?', '{"bonne":1,"choix":["Une famille avec beaucoup de maisons","Une famille incluant grands-parents, oncles, tantes, cousins...","Une famille de riches","Une famille europeenne"],"explication":"La famille elargie comprend les grands-parents, oncles, tantes, cousins et autres parents."}', 'Une famille incluant grands-parents, oncles, tantes, cousins...', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('fc27e97a-e93b-401b-a98e-0abf043348d5', '564de187-8c00-432b-96dd-43e2da552f50', 'qcm', 'Comment s appelle le fils de ton oncle ou de ta tante ?', '{"bonne":2,"choix":["Ton neveu","Ton frere","Ton cousin","Ton filleul"],"explication":"Le fils de ton oncle ou de ta tante est ton cousin."}', 'Ton cousin', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0998c1da-d42b-49c1-91fe-612dd29fe635', '596bfb83-6425-406e-b9ca-80146cfa4f2d', 'qcm', 'Avec 500 F, peut-on acheter 3 articles à 175 F chacun ?', '{"bonne":1,"choix":["Oui, il reste 25 F","Non, il manque 25 F","Oui, il reste 50 F","Non, il manque 50 F"],"explication":"3 × 175 = 525 F > 500 F, donc non, il manque 25 F"}', 'Non, il manque 25 F', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0d127d10-41d9-475d-8f34-fc2e4ae51333', '596bfb83-6425-406e-b9ca-80146cfa4f2d', 'qcm', 'Papa donne un billet de 1 000 F pour acheter du pain à 350 F. Quelle monnaie reçoit-il ?', '{"bonne":2,"choix":["550 F","600 F","650 F","700 F"],"explication":"1 000 - 350 = 650 F"}', '650 F', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('206e6e31-cbb8-4bd4-93b9-1c8afd4bd3fa', '596bfb83-6425-406e-b9ca-80146cfa4f2d', 'qcm', 'Aminata économise 250 F par semaine. Combien aura-t-elle en 4 semaines ?', '{"bonne":2,"choix":["750 F","850 F","1 000 F","1 250 F"],"explication":"250 × 4 = 1 000 F"}', '1 000 F', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('7e07135c-0c28-44e4-98b4-070aa0492750', '596bfb83-6425-406e-b9ca-80146cfa4f2d', 'qcm', 'Koffi achète : pain 200 F, lait 150 F, sucre 100 F. Combien dépense-t-il ?', '{"bonne":2,"choix":["350 F","400 F","450 F","500 F"],"explication":"200 + 150 + 100 = 450 F"}', '450 F', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('83bc8210-b73a-48ee-97d9-0398e569b51a', '596bfb83-6425-406e-b9ca-80146cfa4f2d', 'qcm', 'Yao a 2 500 F. Il achète des livres à 1 750 F. Que lui reste-t-il ?', '{"bonne":1,"choix":["650 F","750 F","850 F","950 F"],"explication":"2 500 - 1 750 = 750 F"}', '750 F', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('9d6e748c-6054-41cd-a925-9f75e7725c66', '596bfb83-6425-406e-b9ca-80146cfa4f2d', 'qcm', 'Fatou a 3 pièces de 100 F et 4 pièces de 25 F. Combien a-t-elle ?', '{"bonne":1,"choix":["375 F","400 F","425 F","450 F"],"explication":"3×100 + 4×25 = 300 + 100 = 400 F"}', '400 F', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a3a357f8-f889-42be-8862-8b240ba6c5bf', '596bfb83-6425-406e-b9ca-80146cfa4f2d', 'qcm', 'Un stylo coûte 75 F. Combien coûtent 4 stylos ?', '{"bonne":2,"choix":["200 F","250 F","300 F","350 F"],"explication":"75 × 4 = 300 F"}', '300 F', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('b537124a-058f-444c-9a88-3fed38fdbb93', '596bfb83-6425-406e-b9ca-80146cfa4f2d', 'qcm', 'Le marché : tomates 300 F, poisson 750 F, huile 400 F. Total ?', '{"bonne":2,"choix":["1 350 F","1 400 F","1 450 F","1 500 F"],"explication":"300 + 750 + 400 = 1 450 F"}', '1 450 F', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('cb75cc24-4529-4ecf-b88a-1f7cafc3d608', '596bfb83-6425-406e-b9ca-80146cfa4f2d', 'qcm', 'Un billet de 5 000 F est échangé contre des billets de 1 000 F. Combien de billets ?', '{"bonne":2,"choix":["3","4","5","6"],"explication":"5 000 ÷ 1 000 = 5 billets"}', '5', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('fd0212f1-4061-4368-ad60-51226154be42', '596bfb83-6425-406e-b9ca-80146cfa4f2d', 'qcm', 'Quel est le plus grand billet de banque utilisé couramment en Côte d''Ivoire ?', '{"bonne":2,"choix":["1 000 F","5 000 F","10 000 F","25 000 F"],"explication":"Le billet de 10 000 F CFA est couramment utilisé"}', '10 000 F', 10) ON CONFLICT (id) DO NOTHING;
