INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('da6210cb-fc60-4fc3-b922-c068eba3733c', '72165ac6-729c-4658-a37f-661b2b657e79', 'qcm', 'Dans quelle region se trouve le massif du Man ?', '{"bonne":2,"choix":["A l est","Au nord","A l ouest","Au sud"],"explication":"Le massif montagneux de Man se trouve a l ouest de la Cote d Ivoire."}', 'A l ouest', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ddf799bd-0588-4b7d-a55f-eade598b96e1', '72165ac6-729c-4658-a37f-661b2b657e79', 'qcm', 'Comment s appelle la lagune sur laquelle est construite Abidjan ?', '{"bonne":1,"choix":["Lagune Ono","Lagune Ebrié","Lagune Aby","Lagune Tendo"],"explication":"Abidjan est construite autour de la lagune Ebrié, la plus grande lagune de CI."}', 'Lagune Ebrié', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('efe24a77-4207-4795-b445-6a59c61826d5', '72165ac6-729c-4658-a37f-661b2b657e79', 'qcm', 'Quel est le plus long fleuve de Cote d Ivoire ?', '{"bonne":1,"choix":["Le Sassandra","La Comoe","Le Bandama","Le Cavally"],"explication":"La Comoe (1160 km) est le plus long fleuve de Cote d Ivoire."}', 'La Comoe', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('090643bf-3edc-437d-837a-6da2ca64a1a9', '82d8c67a-66bc-44c7-bdbd-59ea7fe1fe65', 'qcm', 'Quel est l impact de la deforestation sur le climat ?', '{"bonne":3,"choix":["Aucun impact","Il refroidit le climat","Il augmente les pluies","Il contribue au rechauffement climatique"],"explication":"Les arbres absorbent le CO2. Les couper augmente le CO2 et le rechauffement."}', 'Il contribue au rechauffement climatique', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('18e89404-085d-49f4-9d6a-1bfedbb82686', '82d8c67a-66bc-44c7-bdbd-59ea7fe1fe65', 'qcm', 'Pourquoi proteger les elephants en CI ?', '{"bonne":1,"choix":["Parce qu ils sont dangereux","Parce qu ils sont en danger d extinction et font partie du patrimoine","Parce qu ils mangent tout","Parce qu ils sont trop nombreux"],"explication":"L elephant est le symbole de la CI. Il est menace par le braconnage et la deforestation."}', 'Parce qu ils sont en danger d extinction et font partie du patrimoine', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1a7fd012-ebcf-49b6-855d-70b55827fae4', '82d8c67a-66bc-44c7-bdbd-59ea7fe1fe65', 'qcm', 'Comment appelle-t-on la disparition definitive d une espece animale ?', '{"bonne":1,"choix":["La migration","L extinction","L hibernation","La domestication"],"explication":"L extinction est la disparition definitive de tous les individus d une espece."}', 'L extinction', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1f63ac7e-5859-4159-aacb-0ab0bb70c1dc', '82d8c67a-66bc-44c7-bdbd-59ea7fe1fe65', 'qcm', 'Qu est-ce que la deforestation ?', '{"bonne":1,"choix":["La plantation d arbres","La destruction des forets","Le recyclage du bois","La protection des arbres"],"explication":"La deforestation est la destruction massive des forets par l homme."}', 'La destruction des forets', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('286f84ef-77ae-4267-af48-a3c39237b13f', '82d8c67a-66bc-44c7-bdbd-59ea7fe1fe65', 'qcm', 'Qu est-ce que le recyclage ?', '{"bonne":1,"choix":["Jeter les dechets","Transformer les dechets en nouvelles matieres utiles","Bruler les dechets","Enterrer les dechets"],"explication":"Le recyclage consiste a retraiter les dechets pour en faire de nouveaux produits."}', 'Transformer les dechets en nouvelles matieres utiles', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('685fca2f-b918-435e-bc36-bc8e5e3c6e59', '82d8c67a-66bc-44c7-bdbd-59ea7fe1fe65', 'qcm', 'Qu est-ce qu une energie renouvelable ?', '{"bonne":1,"choix":["Une energie qui se consomme vite","Une energie naturellement reconstituee (soleil, vent, eau)","Une energie tres cherchere","Une energie d origine animale"],"explication":"Les energies renouvelables (solaire, eolien, hydraulique) se reconstituent naturellement."}', 'Une energie naturellement reconstituee (soleil, vent, eau)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('6bcbe055-5021-4c2e-97dc-d20cfd981a27', '82d8c67a-66bc-44c7-bdbd-59ea7fe1fe65', 'qcm', 'Quelle foret est la plus grande d Afrique de l Ouest ?', '{"bonne":2,"choix":["La foret du Ghana","La foret du Nigeria","La foret du Tai en Cote d Ivoire","La foret du Senegal"],"explication":"Le Parc National du Tai en CI est l une des dernieres grandes forets tropicales d Afrique de l Ouest."}', 'La foret du Tai en Cote d Ivoire', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('aa40d4a8-7ca4-4186-8715-3ea628728bb8', '82d8c67a-66bc-44c7-bdbd-59ea7fe1fe65', 'qcm', 'Pourquoi ne faut-il pas jeter les plastiques dans la nature ?', '{"bonne":1,"choix":["Ca fait de la maladie directement","Ils mettent des centaines d annees a se degrader et polluent","Ils font peur aux animaux","Ils bouchent les pluies"],"explication":"Les plastiques persistent pendant 400 a 1000 ans dans la nature et polluent."}', 'Ils mettent des centaines d annees a se degrader et polluent', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d5f4b346-e624-4a7b-a245-d40a48c29645', '82d8c67a-66bc-44c7-bdbd-59ea7fe1fe65', 'qcm', 'Quel est le principal gaz a effet de serre ?', '{"bonne":2,"choix":["L oxygene","L azote","Le dioxyde de carbone (CO2)","L hydrogene"],"explication":"Le CO2 est le principal gaz responsable de l effet de serre et du rechauffement climatique."}', 'Le dioxyde de carbone (CO2)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f00eb80a-9ef6-4e08-b167-14044cf0e9fb', '82d8c67a-66bc-44c7-bdbd-59ea7fe1fe65', 'qcm', 'Qu est-ce que le developpement durable ?', '{"bonne":1,"choix":["Construire plus vite","Satisfaire les besoins d aujourd hui sans compromettre ceux des generations futures","Utiliser toutes les ressources naturelles","Exporter plus de produits"],"explication":"Le developpement durable concilie developpement economique et preservation de l environnement."}', 'Satisfaire les besoins d aujourd hui sans compromettre ceux des generations futures', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1b94e567-83bc-4489-bf0d-d1d6a9dbd493', '84b2f593-5665-440f-9696-5b9c9b2bed1d', 'qcm', 'Accorde le verbe : "Toi et moi ___ (être) amis."', '{"bonne":2,"choix":["es","sont","sommes","êtes"],"explication":"\"Toi et moi\" = nous deux → 1ère pers. pluriel → \"sommes\""}', 'sommes', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1edbdd4e-021d-48a7-8bc5-ba1b3a374e07', '84b2f593-5665-440f-9696-5b9c9b2bed1d', 'qcm', 'Laquelle est correcte ?', '{"bonne":1,"choix":["Vous mangeons ensemble.","Vous mangez ensemble.","Vous mangeait ensemble.","Vous mangeons ensemble."],"explication":"\"Vous\" → 2e pers. pluriel → \"mangez\""}', 'Vous mangez ensemble.', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('26b8e4d2-4ae0-43b8-950e-7ddf48b62d83', '84b2f593-5665-440f-9696-5b9c9b2bed1d', 'qcm', 'Laquelle est correcte ?', '{"bonne":1,"choix":["Aminata et Kofi chante.","Aminata et Kofi chantent.","Aminata et Kofi chantes.","Aminata et Kofi chantons."],"explication":"Sujet composé pluriel → verbe au pluriel : \"chantent\""}', 'Aminata et Kofi chantent.', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('59c646ee-ff1a-461a-984a-0343b168b56d', '84b2f593-5665-440f-9696-5b9c9b2bed1d', 'qcm', 'Laquelle est incorrecte ?', '{"bonne":2,"choix":["Je chante.","Tu chantes.","Il chantent.","Nous chantons."],"explication":"\"Il chantent\" est faux. \"Il\" = singulier → \"il chante\""}', 'Il chantent.', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('640fe0a3-cfff-4d9a-b681-aa3dcfcab520', '84b2f593-5665-440f-9696-5b9c9b2bed1d', 'qcm', 'Accorde le verbe : "Les enfants ___ (dormir)."', '{"bonne":2,"choix":["dort","dors","dorment","dormez"],"explication":"\"Les enfants\" → 3e pers. pluriel → \"dorment\""}', 'dorment', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('83587022-e37b-4ed2-9218-e5ba1b104c66', '84b2f593-5665-440f-9696-5b9c9b2bed1d', 'qcm', 'Accorde le verbe : "L''oiseau ___ (chanter) sur la branche."', '{"bonne":2,"choix":["chantent","chantons","chante","chantez"],"explication":"\"L''oiseau\" → 3e pers. sing. → \"chante\""}', 'chante', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('cf74ee17-d110-435c-8167-7dae87b42862', '84b2f593-5665-440f-9696-5b9c9b2bed1d', 'qcm', 'Accorde le verbe : "Nous ___ (jouer) au football."', '{"bonne":2,"choix":["joue","joues","jouons","jouent"],"explication":"Nous → 1ère pers. pluriel → \"jouons\""}', 'jouons', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e6a31178-40e9-452a-ae8b-3a3ab6e288d7', '84b2f593-5665-440f-9696-5b9c9b2bed1d', 'qcm', 'Le verbe s''accorde toujours avec :', '{"bonne":1,"choix":["Le complément","Le sujet","L''adjectif","L''article"],"explication":"Le verbe s''accorde TOUJOURS avec son sujet en personne et en nombre."}', 'Le sujet', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('eb5b5833-1816-4415-9e52-923e760cceac', '84b2f593-5665-440f-9696-5b9c9b2bed1d', 'qcm', 'Laquelle est correcte ?', '{"bonne":1,"choix":["Les chiens aboie.","Les chiens aboient.","Les chiens aboit.","Le chien aboient."],"explication":"Sujet pluriel \"Les chiens\" → verbe pluriel \"aboient\""}', 'Les chiens aboient.', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f0fdf4be-9437-4ed0-9b26-81a50d0a95c8', '84b2f593-5665-440f-9696-5b9c9b2bed1d', 'qcm', 'Accorde le verbe : "Vous ___ (finir) votre travail."', '{"bonne":2,"choix":["finis","finit","finissez","finissent"],"explication":"Vous → 2e pers. pluriel → \"finissez\""}', 'finissez', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('188d9aab-b122-4475-a041-88f85f227365', '85d494b7-3b1e-42e9-9ed1-043168dee906', 'qcm', 'Comment s appelle le passage du liquide au solide ?', '{"bonne":2,"choix":["La fusion","L evaporation","La solidification","La condensation"],"explication":"La solidification est le passage de l etat liquide a l etat solide."}', 'La solidification', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('39fb34b6-267c-4634-99d4-e30cf5882477', '85d494b7-3b1e-42e9-9ed1-043168dee906', 'qcm', 'Quel est l etat de l eau dans un verre ?', '{"bonne":1,"choix":["Solide","Liquide","Gazeux","Plasma"],"explication":"L eau dans un verre est a l etat liquide."}', 'Liquide', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('4021607d-e3a9-43a3-96ed-cac4b1165ac4', '85d494b7-3b1e-42e9-9ed1-043168dee906', 'qcm', 'Quelle est la matiere la plus dense : le fer, le bois ou la mousse ?', '{"bonne":2,"choix":["La mousse","Le bois","Le fer","Ils ont la meme densite"],"explication":"Le fer est bien plus dense (lourd pour son volume) que le bois ou la mousse."}', 'Le fer', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('40b85f48-e30e-46ca-a204-940ad8a3feac', '85d494b7-3b1e-42e9-9ed1-043168dee906', 'qcm', 'Comment s appelle le passage du solide au liquide ?', '{"bonne":1,"choix":["La solidification","La fusion","L evaporation","La sublimation"],"explication":"La fusion est le passage de l etat solide a l etat liquide."}', 'La fusion', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('7602f486-28bc-44a0-aa61-7d3f2abb51a1', '85d494b7-3b1e-42e9-9ed1-043168dee906', 'qcm', 'Un liquide a-t-il un volume fixe ?', '{"bonne":1,"choix":["Non","Oui, son volume ne change pas","Parfois","Non, il se dilate"],"explication":"Un liquide a un volume fixe mais prend la forme du recipient qui le contient."}', 'Oui, son volume ne change pas', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('81f6a350-fb6c-4baa-9a3d-423f69aaf4e8', '85d494b7-3b1e-42e9-9ed1-043168dee906', 'qcm', 'Quel est l etat de la vapeur d eau ?', '{"bonne":2,"choix":["Solide","Liquide","Gazeux","Solide et liquide"],"explication":"La vapeur d eau est de l eau a l etat gazeux."}', 'Gazeux', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c00d2b9f-2ffe-41ac-894e-b9993c5e7a3d', '85d494b7-3b1e-42e9-9ed1-043168dee906', 'qcm', 'Le beurre fond-il quand on le chauffe ?', '{"bonne":1,"choix":["Non","Oui, il passe du solide au liquide","Oui, il passe au gazeux","Non, il brule"],"explication":"Le beurre fond (fusion) quand on le chauffe, passant du solide au liquide."}', 'Oui, il passe du solide au liquide', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c3c77941-2762-4de3-b45b-171016cd5661', '85d494b7-3b1e-42e9-9ed1-043168dee906', 'qcm', 'Un solide a-t-il une forme propre ?', '{"bonne":1,"choix":["Non, il prend la forme du recipient","Oui, sa forme est fixe","Parfois","Ca depend de la temperature"],"explication":"Un solide conserve sa propre forme independamment du recipient."}', 'Oui, sa forme est fixe', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('cae0d2f0-b7b6-4554-afb0-2d0cb276a2ff', '85d494b7-3b1e-42e9-9ed1-043168dee906', 'qcm', 'Quelle propriete caracterise les gaz ?', '{"bonne":2,"choix":["Ils ont une forme fixe","Ils ont un volume fixe","Ils occupent tout l espace disponible","Ils sont toujours lourds"],"explication":"Les gaz occupent tout le volume du recipient qui les contient."}', 'Ils occupent tout l espace disponible', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f02c5d19-6871-4c45-a014-7e2db3652110', '85d494b7-3b1e-42e9-9ed1-043168dee906', 'qcm', 'Comment s appelle le changement direct de solide en gaz ?', '{"bonne":2,"choix":["La fusion","L evaporation","La sublimation","La condensation"],"explication":"La sublimation est le passage direct de l etat solide a l etat gazeux."}', 'La sublimation', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('059018a7-6c17-4734-a206-59e2fcd2e91a', '861b3adc-aa00-45f6-b12f-2bc9594d32cb', 'qcm', 'Quelle fraction représente un quart ?', '{"bonne":2,"choix":["1/2","1/3","1/4","1/5"],"explication":"Un quart = 1/4 (on partage en 4 parts égales et on prend 1)"}', '1/4', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('05d296cb-7d05-421b-89e3-2cea046bd58a', '861b3adc-aa00-45f6-b12f-2bc9594d32cb', 'qcm', 'Un gâteau est coupé en 8 parts. Kofi mange 2 parts. Quelle fraction a-t-il mangée ?', '{"bonne":1,"choix":["1/8","2/8","3/8","4/8"],"explication":"2 parts sur 8 = 2/8 = 1/4 du gâteau"}', '2/8', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('40fd80ef-489b-41d2-8ac1-8ffac6072d37', '861b3adc-aa00-45f6-b12f-2bc9594d32cb', 'qcm', 'Quelle fraction est la plus grande : 1/4 ou 1/2 ?', '{"bonne":1,"choix":["1/4","1/2","Elles sont égales","Impossible à dire"],"explication":"1/2 > 1/4 car une demie est plus grande qu''un quart"}', '1/2', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('43bab23f-5220-47a0-91a3-d5f558b35197', '861b3adc-aa00-45f6-b12f-2bc9594d32cb', 'qcm', 'Dans une classe de 30 élèves, 1/3 sont absents. Combien sont absents ?', '{"bonne":1,"choix":["5","10","15","20"],"explication":"1/3 de 30 = 30 ÷ 3 = 10 élèves absents"}', '10', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('4c399344-4b05-4768-ad4a-329d499b4ea3', '861b3adc-aa00-45f6-b12f-2bc9594d32cb', 'qcm', 'Laquelle de ces fractions est égale à 1/2 ?', '{"bonne":1,"choix":["2/6","3/6","4/6","5/6"],"explication":"3/6 = 1/2 (on peut simplifier : 3÷3=1 et 6÷3=2)"}', '3/6', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('4f04c24e-fe3f-453e-91cb-fa311559e8e8', '861b3adc-aa00-45f6-b12f-2bc9594d32cb', 'qcm', 'Quelle fraction correspond à "deux tiers" ?', '{"bonne":1,"choix":["2/2","2/3","3/2","1/3"],"explication":"Deux tiers s''écrit 2/3"}', '2/3', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('87397029-bf82-4302-b1d8-2383a9b88c4a', '861b3adc-aa00-45f6-b12f-2bc9594d32cb', 'qcm', 'Laquelle de ces fractions est la plus petite ?', '{"bonne":3,"choix":["1/2","1/3","1/4","1/6"],"explication":"1/6 est la plus petite car on divise en plus de parts"}', '1/6', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('b6403428-93be-4dfe-9d3a-a76fc6f657da', '861b3adc-aa00-45f6-b12f-2bc9594d32cb', 'qcm', 'Une orange est coupée en 4 parts. Aminata mange 3 parts. Quelle fraction a-t-elle mangée ?', '{"bonne":2,"choix":["1/4","2/4","3/4","4/4"],"explication":"3 parts sur 4 = 3/4 de l''orange"}', '3/4', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c5aaa766-c5b4-44e3-87cc-e0f2abe295d6', '861b3adc-aa00-45f6-b12f-2bc9594d32cb', 'qcm', 'Quelle fraction est égale à un entier ?', '{"bonne":2,"choix":["2/3","3/4","4/4","1/4"],"explication":"4/4 = 1 entier (toutes les parts = le tout)"}', '4/4', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c62a1a77-bb53-46ff-8134-caa215a23ba3', '861b3adc-aa00-45f6-b12f-2bc9594d32cb', 'qcm', 'Un ruban mesure 1 m. On coupe 3/4 du ruban. Quelle longueur a-t-on coupée ?', '{"bonne":2,"choix":["25 cm","50 cm","75 cm","100 cm"],"explication":"3/4 de 100 cm = 75 cm"}', '75 cm', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('028e1214-be85-4f2b-b420-6725c247a0bf', '88b45562-0b89-4881-98ff-dedccb93b7a1', 'qcm', 'Qu est-ce qu un interrupteur ?', '{"bonne":1,"choix":["Un fil electrique","Un dispositif qui ouvre ou ferme un circuit","Une ampoule","Un generateur"],"explication":"L interrupteur permet d ouvrir ou de fermer le circuit electrique."}', 'Un dispositif qui ouvre ou ferme un circuit', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('129d16e9-e982-4a5c-bacd-2876fb3238e0', '88b45562-0b89-4881-98ff-dedccb93b7a1', 'qcm', 'Qu est-ce que l electricite ?', '{"bonne":1,"choix":["De la lumiere","Un deplacement d electrons (courant electrique)","De la chaleur","Du son"],"explication":"L electricite est un deplacement de charges electriques (electrons) dans un conducteur."}', 'Un deplacement d electrons (courant electrique)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('19313fe2-6156-4af9-89fb-1b0eff73b604', '88b45562-0b89-4881-98ff-dedccb93b7a1', 'qcm', 'Que produit une ampoule quand le courant la traverse ?', '{"bonne":1,"choix":["Du son","De la lumiere et de la chaleur","De l eau","Du vent"],"explication":"Une ampoule transforme l electricite en lumiere et en chaleur."}', 'De la lumiere et de la chaleur', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('20936653-2bea-4fc2-a978-c11aa38a1108', '88b45562-0b89-4881-98ff-dedccb93b7a1', 'qcm', 'Pourquoi ne faut-il pas brancher trop d appareils sur une prise ?', '{"bonne":1,"choix":["Pour economiser la place","Pour eviter la surcharge et le court-circuit","Pour pas payer trop","Parce que ca ne marche pas"],"explication":"Trop d appareils sur une prise peut provoquer une surcharge et un incendie."}', 'Pour eviter la surcharge et le court-circuit', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('55b0fa23-2ba8-44aa-b564-7ecec9ea8306', '88b45562-0b89-4881-98ff-dedccb93b7a1', 'qcm', 'Comment produit-on l electricite en Cote d Ivoire ?', '{"bonne":2,"choix":["Uniquement avec des barrages","Avec du soleil seulement","Avec des barrages hydrauliques et des centrales thermiques","Avec le vent seulement"],"explication":"La CI produit son electricite grace a des barrages (Kossou, Ayame) et des centrales au gaz."}', 'Avec des barrages hydrauliques et des centrales thermiques', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a0f1ee54-f0bf-4f1e-8f01-bb5eff76407e', '88b45562-0b89-4881-98ff-dedccb93b7a1', 'qcm', 'Qu est-ce qu un fusible ?', '{"bonne":1,"choix":["Un type d ampoule","Un dispositif de protection qui coupe en cas de surcharge","Un type de pile","Un interrupteur special"],"explication":"Le fusible protege le circuit en se cassant en cas de surintensité."}', 'Un dispositif de protection qui coupe en cas de surcharge', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ac7c4b93-a765-437e-9920-e49e7be77325', '88b45562-0b89-4881-98ff-dedccb93b7a1', 'qcm', 'Qu est-ce qu une pile electrique ?', '{"bonne":1,"choix":["Un stockage d eau","Un objet qui transforme l energie chimique en electricite","Un transformateur de lumiere","Un aimant"],"explication":"Une pile transforme l energie chimique en energie electrique."}', 'Un objet qui transforme l energie chimique en electricite', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c5395529-922a-4d23-94f7-d646ee3eff7f', '88b45562-0b89-4881-98ff-dedccb93b7a1', 'qcm', 'Lequel de ces materiaux est un bon conducteur ?', '{"bonne":2,"choix":["Le bois","Le plastique","Le cuivre","Le verre"],"explication":"Le cuivre est un excellent conducteur electrique, utilise dans les fils electriques."}', 'Le cuivre', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c6e28bc6-c6fb-4937-823e-edb16525e758', '88b45562-0b89-4881-98ff-dedccb93b7a1', 'qcm', 'Qu est-ce qu un conducteur electrique ?', '{"bonne":1,"choix":["Un materiau qui s echauffe","Un materiau qui laisse passer le courant","Un materiau qui bloque le courant","Un materiau transparent"],"explication":"Les conducteurs (metaux) laissent passer facilement le courant electrique."}', 'Un materiau qui laisse passer le courant', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ca6b228a-43a4-4e1a-91d5-243a7280f9b4', '88b45562-0b89-4881-98ff-dedccb93b7a1', 'qcm', 'Pourquoi ne faut-il pas toucher les fils electriques ?', '{"bonne":1,"choix":["Parce qu ils font du bruit","Parce que l electricite peut tuer","Parce qu ils sont sales","Parce qu ils sont fragiles"],"explication":"Le courant electrique peut provoquer des electrocutions mortelles."}', 'Parce que l electricite peut tuer', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('04dc77fb-9891-4e23-8214-745cb069d3f7', '8b5782a9-1005-43f4-87f5-a026b7b09798', 'qcm', 'Combien de jours y a-t-il en février (année non bissextile) ?', '{"bonne":0,"choix":["28","29","30","31"],"explication":"Février a 28 jours (29 les années bissextiles)"}', '28', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('20c8c8e6-3f7b-4eb1-a04c-10f36c2eb887', '8b5782a9-1005-43f4-87f5-a026b7b09798', 'qcm', 'Kofi est né en 2016. Quel âge a-t-il en 2024 ?', '{"bonne":2,"choix":["6 ans","7 ans","8 ans","9 ans"],"explication":"2024 - 2016 = 8 ans"}', '8 ans', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('232082a3-aee5-454e-81a7-5b394235927f', '8b5782a9-1005-43f4-87f5-a026b7b09798', 'qcm', 'Combien de jours y a-t-il dans une semaine ?', '{"bonne":2,"choix":["5","6","7","8"],"explication":"Une semaine = 7 jours (lundi au dimanche)"}', '7', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('43ca0c18-c911-4269-9184-ec2c4822cc6f', '8b5782a9-1005-43f4-87f5-a026b7b09798', 'qcm', 'Combien de minutes y a-t-il dans 1 heure ?', '{"bonne":2,"choix":["24","30","60","100"],"explication":"1 heure = 60 minutes"}', '60', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('6a531509-8c19-43d6-8e14-fae85f46d9f2', '8b5782a9-1005-43f4-87f5-a026b7b09798', 'qcm', 'Quelle heure est-il si l''aiguille des heures indique 3 et celle des minutes indique 12 ?', '{"bonne":1,"choix":["12h 03","3h 00","3h 12","12h 03"],"explication":"L''aiguille des heures sur 3 et celle des minutes sur 12 = 3h 00"}', '3h 00', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('86774722-8f4f-4e5c-955f-73f59c9c5458', '8b5782a9-1005-43f4-87f5-a026b7b09798', 'qcm', 'Quel mois vient après octobre ?', '{"bonne":1,"choix":["Septembre","Novembre","Décembre","Août"],"explication":"L''ordre des mois : ...septembre, octobre, novembre, décembre"}', 'Novembre', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('bea4b4e5-12bd-44e0-a316-5aca6e75ce50', '8b5782a9-1005-43f4-87f5-a026b7b09798', 'qcm', 'Combien de secondes y a-t-il dans 1 minute ?', '{"bonne":1,"choix":["24","60","100","30"],"explication":"1 minute = 60 secondes"}', '60', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d431f1bd-4a0a-4b4f-a24f-7905742697d3', '8b5782a9-1005-43f4-87f5-a026b7b09798', 'qcm', 'Un film dure 1h 45 min. Il commence à 15h 00. À quelle heure se termine-t-il ?', '{"bonne":1,"choix":["16h 30","16h 45","17h 00","17h 15"],"explication":"15h 00 + 1h 45 min = 16h 45"}', '16h 45', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d5bcfc85-c9ff-4f4c-a076-bc7a8bf4fdd0', '8b5782a9-1005-43f4-87f5-a026b7b09798', 'qcm', 'L''école commence à 7h 30. La récréation est à 10h 00. Combien de temps avant la récréation ?', '{"bonne":2,"choix":["1h 30","2h 00","2h 30","3h 00"],"explication":"De 7h 30 à 10h 00 = 2h 30 min"}', '2h 30', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d7821583-8035-4bec-9a69-c37d3c2bde55', '8b5782a9-1005-43f4-87f5-a026b7b09798', 'qcm', 'Combien de mois y a-t-il dans 1 an ?', '{"bonne":3,"choix":["4","7","10","12"],"explication":"1 an = 12 mois"}', '12', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('084884a1-1d91-4bae-a257-c5caa3c499c9', '91fa7ed3-09a7-4ca7-ada0-33f9a0e795b6', 'qcm', 'Le prix d''un livre est 1 250 F. Avec 5 000 F, combien de livres peut-on acheter ?', '{"bonne":2,"choix":["2","3","4","5"],"explication":"5 000 ÷ 1 250 = 4 livres"}', '4', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('15d358aa-ceae-4949-8928-706e330ac4f4', '91fa7ed3-09a7-4ca7-ada0-33f9a0e795b6', 'qcm', 'Aminata achète 3 cahiers à 150 F et 2 stylos à 75 F. Combien dépense-t-elle ?', '{"bonne":1,"choix":["575 F","600 F","625 F","650 F"],"explication":"3×150 + 2×75 = 450 + 150 = 600 F"}', '600 F', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('195d9e7b-439e-4263-8a86-b55e21f353f3', '91fa7ed3-09a7-4ca7-ada0-33f9a0e795b6', 'qcm', 'Une classe a 38 élèves. 15 sont absents. Combien sont présents ?', '{"bonne":1,"choix":["13","23","33","43"],"explication":"38 - 15 = 23 élèves présents"}', '23', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1bccc14f-f07f-456b-96ee-ae25c69adadf', '91fa7ed3-09a7-4ca7-ada0-33f9a0e795b6', 'qcm', 'Un sac de riz pèse 25 kg. Combien pèsent 6 sacs ?', '{"bonne":3,"choix":["120 kg","130 kg","140 kg","150 kg"],"explication":"25 × 6 = 150 kg"}', '150 kg', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('89f9ade3-dc73-47e5-a655-200ef14e672c', '91fa7ed3-09a7-4ca7-ada0-33f9a0e795b6', 'qcm', 'Un fermier a 250 poules. Il en vend 75 et en achète 40. Combien a-t-il maintenant ?', '{"bonne":2,"choix":["195","205","215","225"],"explication":"250 - 75 + 40 = 175 + 40 = 215 poules"}', '215', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('97f421ea-ac7d-47bd-a800-666a4e13b779', '91fa7ed3-09a7-4ca7-ada0-33f9a0e795b6', 'qcm', 'On répartit 96 stylos entre 8 enfants. Combien chacun reçoit-il ?', '{"bonne":2,"choix":["10","11","12","13"],"explication":"96 ÷ 8 = 12 stylos chacun"}', '12', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('aad6c03b-716b-4eec-9831-90d6910f8ab5', '91fa7ed3-09a7-4ca7-ada0-33f9a0e795b6', 'qcm', 'Yao épargne 500 F par semaine. En combien de semaines aura-t-il 4 000 F ?', '{"bonne":2,"choix":["6","7","8","9"],"explication":"4 000 ÷ 500 = 8 semaines"}', '8', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e5c77d3a-7aaf-44b4-ade4-e23332e1957d', '91fa7ed3-09a7-4ca7-ada0-33f9a0e795b6', 'qcm', 'Une piscine contient 8 500 L. On vide 3 750 L. Combien reste-t-il ?', '{"bonne":1,"choix":["4 650 L","4 750 L","5 650 L","4 850 L"],"explication":"8 500 - 3 750 = 4 750 L"}', '4 750 L', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f3683967-7b08-4a1a-9beb-6823834c20df', '91fa7ed3-09a7-4ca7-ada0-33f9a0e795b6', 'qcm', 'Un marchand vend 245 oranges le lundi et 312 le mardi. Combien en tout ?', '{"bonne":1,"choix":["547","557","567","577"],"explication":"245 + 312 = 557 oranges"}', '557', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f9a719bf-fc63-4359-acf2-c0292f617c6d', '91fa7ed3-09a7-4ca7-ada0-33f9a0e795b6', 'qcm', 'Un train part à 6h 30 et arrive à 9h 15. Combien de temps dure le voyage ?', '{"bonne":2,"choix":["2h 15 min","2h 30 min","2h 45 min","3h 00 min"],"explication":"De 6h30 à 9h15 = 2h 45 min"}', '2h 45 min', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('34b11e62-8c68-436a-afe2-548db698c04e', '9a038120-5752-4f7b-998f-d9978701f5ee', 'qcm', 'Quand utilise-t-on "l''" à la place de "le" ou "la" ?', '{"bonne":1,"choix":["Devant une consonne","Devant une voyelle ou h muet","Toujours","Jamais"],"explication":"On utilise \"l''\" devant les mots qui commencent par une voyelle ou h muet (l''arbre, l''heure)"}', 'Devant une voyelle ou h muet', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('37a9418e-5374-479c-ac99-ef31985cfbfd', '9a038120-5752-4f7b-998f-d9978701f5ee', 'qcm', 'Quelle est la différence entre "le" et "un" ?', '{"bonne":1,"choix":["\"Le\" est indéfini, \"un\" est défini","\"Le\" est défini, \"un\" est indéfini","Ils sont identiques","Il n''y a pas de règle"],"explication":"\"Le/la/les\" sont des articles définis (on sait lequel). \"Un/une/des\" sont indéfinis."}', '"Le" est défini, "un" est indéfini', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('4d1b1b95-be95-45ea-b741-bd658eb9b044', '9a038120-5752-4f7b-998f-d9978701f5ee', 'qcm', 'Quel article indéfini convient ? Je vois ___ éléphant.', '{"bonne":2,"choix":["le","la","un","une"],"explication":"\"Éléphant\" est masculin singulier → article indéfini : \"un\""}', 'un', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('678b95b5-4d6d-4939-88df-a997aa6b8716', '9a038120-5752-4f7b-998f-d9978701f5ee', 'qcm', 'Transforme au pluriel : "un cahier" →', '{"bonne":2,"choix":["un cahiers","des cahier","des cahiers","les cahier"],"explication":"Article indéfini pluriel = \"des\", nom pluriel = \"cahiers\" → \"des cahiers\""}', 'des cahiers', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('840713ba-c057-4a45-a313-a224ccea1d98', '9a038120-5752-4f7b-998f-d9978701f5ee', 'qcm', 'Complète : "J''ai acheté ___ livres au marché."', '{"bonne":3,"choix":["le","la","un","des"],"explication":"\"Livres\" est pluriel → article indéfini pluriel : \"des\""}', 'des', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c1d429f1-d6f1-4242-b558-51efa467b925', '9a038120-5752-4f7b-998f-d9978701f5ee', 'qcm', 'Quel article indéfini convient ? Elle a ___ belle robe.', '{"bonne":3,"choix":["le","la","un","une"],"explication":"\"Robe\" est féminin → article indéfini féminin : \"une\""}', 'une', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ce4e2141-aa9f-4279-a7df-cadc684b1b61', '9a038120-5752-4f7b-998f-d9978701f5ee', 'qcm', 'Quel article convient ? ___ orange est sucrée.', '{"bonne":2,"choix":["Le","Un","La","Une"],"explication":"\"Orange\" est féminin → \"la\" (défini) ou \"une\" (indéfini). Ici \"La orange\" → \"L''orange\". Mais parmi les choix : \"La\""}', 'La', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d656b313-f931-4c98-a7ce-c41c31e94dce', '9a038120-5752-4f7b-998f-d9978701f5ee', 'qcm', 'Complète : "___ soleil brille fort aujourd''hui."', '{"bonne":2,"choix":["Un","Une","Le","La"],"explication":"\"Soleil\" est masculin défini → \"Le soleil\""}', 'Le', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f2ae8288-e2de-445b-9a56-6cf2458f0ad0', '9a038120-5752-4f7b-998f-d9978701f5ee', 'qcm', 'Quel article défini convient ? ___ enfants jouent.', '{"bonne":3,"choix":["Un","Une","Le","Les"],"explication":"\"Enfants\" est pluriel → article défini pluriel : \"les\""}', 'Les', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('fb2a681c-10ea-48d0-8f25-af610f1ad7bc', '9a038120-5752-4f7b-998f-d9978701f5ee', 'qcm', 'Quel article défini pluriel utilise-t-on avec "filles" ?', '{"bonne":2,"choix":["le","la","les","des"],"explication":"\"Les\" est l''article défini pluriel pour les deux genres."}', 'les', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('02e6281a-148f-4bc9-9454-5a452993b419', 'a708f881-0051-4efe-90f9-543cdea90678', 'qcm', 'Pourquoi paie-t-on des impots ?', '{"bonne":1,"choix":["Pour enrichir le president","Pour financer les services publics : ecoles, hopitaux, routes...","Parce qu on n a pas le choix","Pour payer les policiers seulement"],"explication":"Les impots financent les services publics dont toute la population beneficie."}', 'Pour financer les services publics : ecoles, hopitaux, routes...', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('467349d4-ceb3-41e4-aa28-e112b48a18cf', 'a708f881-0051-4efe-90f9-543cdea90678', 'qcm', 'Quel service public assure le transport en commun a Abidjan ?', '{"bonne":2,"choix":["Air Ivoire","La SODECI","La SOTRA","La CIE"],"explication":"La SOTRA (Societe des Transports Abidjanais) gere les bus de transport en commun a Abidjan."}', 'La SOTRA', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('72bf2657-b822-4684-9899-c63c7a2b8f77', 'a708f881-0051-4efe-90f9-543cdea90678', 'qcm', 'Que fait la CIE (Compagnie Ivoirienne d Electricite) ?', '{"bonne":1,"choix":["Distribue l eau potable","Distribue l electricite en CI","Construit les routes","Gere les ecoles"],"explication":"La CIE est la societe qui distribue et commercialise l electricite en Cote d Ivoire."}', 'Distribue l electricite en CI', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('926a1015-6a02-49f5-9a40-0fdfefcbfafd', 'a708f881-0051-4efe-90f9-543cdea90678', 'qcm', 'Qu est-ce que le CHU ?', '{"bonne":1,"choix":["Centre d Hebergement Universitaire","Centre Hospitalier Universitaire","Conseil des Habitants Urbains","Comptoir d Habillage Urbain"],"explication":"Le CHU est un grand hopital public qui assure a la fois les soins et la formation medicale."}', 'Centre Hospitalier Universitaire', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a420e35b-1afa-4c81-9351-401b7092fc2a', 'a708f881-0051-4efe-90f9-543cdea90678', 'qcm', 'Qu est-ce que la securite sociale ?', '{"bonne":1,"choix":["La surveillance des rues","Un systeme qui protege les travailleurs contre les risques (maladie, accident, retraite)","Un syndicat","Un type d assurance prive"],"explication":"La securite sociale protege les travailleurs et leurs familles contre divers risques de la vie."}', 'Un systeme qui protege les travailleurs contre les risques (maladie, accident, retraite)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('acc6702f-5b2c-41d7-92b0-956b163d1749', 'a708f881-0051-4efe-90f9-543cdea90678', 'qcm', 'Qui construit et entretient les routes en CI ?', '{"bonne":1,"choix":["Les communes seules","Le ministere de la Construction et des Infrastructures","Les entreprises privees uniquement","Les citoyens eux-memes"],"explication":"L Etat, via le ministere des Infrastructures, finance et supervise la construction des routes."}', 'Le ministere de la Construction et des Infrastructures', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c5918fdf-7109-49ed-8436-3fd3ee0f174a', 'a708f881-0051-4efe-90f9-543cdea90678', 'qcm', 'Quel document prouve votre identite en CI ?', '{"bonne":1,"choix":["Le carnet de sante","La carte nationale d identite (CNI)","Le livret de famille","Le bulletin de salaire"],"explication":"La carte nationale d identite est le document officiel prouvant l identite d un citoyen ivoirien."}', 'La carte nationale d identite (CNI)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d9306ece-81d9-4aa1-9ede-b483e145c95c', 'a708f881-0051-4efe-90f9-543cdea90678', 'qcm', 'Quel service public s occupe de la sante des citoyens ?', '{"bonne":1,"choix":["La police","L hopital et les centres de sante","Les ecoles","La mairie"],"explication":"Les hopitaux et centres de sante sont des services publics de sante."}', 'L hopital et les centres de sante', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('de92ca95-ba9a-488b-b39a-87509a06a045', 'a708f881-0051-4efe-90f9-543cdea90678', 'qcm', 'A quoi sert la poste ?', '{"bonne":1,"choix":["A vendre des timbres uniquement","A transporter le courrier, les colis, et proposer des services financiers","A reparer les routes","A surveiller les quartiers"],"explication":"La Poste assure le transport du courrier, des colis et offre des services financiers aux citoyens."}', 'A transporter le courrier, les colis, et proposer des services financiers', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f29aaa3d-7557-4346-9d22-d502d18cb28e', 'a708f881-0051-4efe-90f9-543cdea90678', 'qcm', 'Qu est-ce qu un service public ?', '{"bonne":1,"choix":["Un magasin prive","Un service organise par l Etat pour repondre aux besoins de tous","Un restaurant","Un marche prive"],"explication":"Les services publics sont organises par l Etat pour satisfaire les besoins essentiels des citoyens."}', 'Un service organise par l Etat pour repondre aux besoins de tous', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('03d5dc14-b313-4540-80a6-2bb211b76618', 'a9bb0f5f-ddb3-4703-8e28-f9368df3d4aa', 'qcm', 'Quelle est la principale regle dans une classe ?', '{"bonne":1,"choix":["Faire ce qu on veut","Ecouter le maitre, lever la main pour parler, respecter les camarades","Copier sur son voisin","Parler fort"],"explication":"Ecouter le maitre, demander la parole et respecter les autres sont les regles fondamentales."}', 'Ecouter le maitre, lever la main pour parler, respecter les camarades', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0b39f2a2-e443-42d7-a565-a4d073c50d1f', 'a9bb0f5f-ddb3-4703-8e28-f9368df3d4aa', 'qcm', 'Qu est-ce que la cooperation en classe ?', '{"bonne":1,"choix":["Copier sur son voisin","Travailler ensemble et s entraider pour apprendre","Faire le travail des autres","Se partager les bonnes notes"],"explication":"La cooperation c est travailler ensemble de facon positive pour apprendre et progresser."}', 'Travailler ensemble et s entraider pour apprendre', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('13fdba56-f3ae-4bee-86eb-d8d15ce47fae', 'a9bb0f5f-ddb3-4703-8e28-f9368df3d4aa', 'qcm', 'Que signifie respecter ses camarades ?', '{"bonne":1,"choix":["Tout leur donner","Traiter ses camarades comme on aimerait etre traite soi-meme","Les ignorer","Toujours etre d accord avec eux"],"explication":"Respecter ses camarades signifie les traiter avec bienveillance, comme on souhaiterait l etre."}', 'Traiter ses camarades comme on aimerait etre traite soi-meme', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('2e3b691a-d13e-4cb5-980f-773fb3b2bb26', 'a9bb0f5f-ddb3-4703-8e28-f9368df3d4aa', 'qcm', 'Pourquoi doit-on prendre soin du materiel scolaire ?', '{"bonne":1,"choix":["Pour impressionner les camarades","Parce que c est un bien commun ou un bien offert par les parents, a respecter","Parce que le maitre le surveille","Pour le vendre plus tard"],"explication":"Le materiel scolaire a ete fourni avec des efforts et doit etre traite avec respect."}', 'Parce que c est un bien commun ou un bien offert par les parents, a respecter', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('3043e4c7-81e7-4d3a-bafa-7a761d0a21eb', 'a9bb0f5f-ddb3-4703-8e28-f9368df3d4aa', 'qcm', 'En Cote d Ivoire, l education est-elle obligatoire ?', '{"bonne":1,"choix":["Non","Oui, jusqu a l age de 16 ans","Oui, mais seulement pour les garcons","Non, c est un choix"],"explication":"En CI, l education est obligatoire pour tous les enfants de 6 a 16 ans."}', 'Oui, jusqu a l age de 16 ans', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('954e2919-6204-4a3d-a42c-86ef05f679be', 'a9bb0f5f-ddb3-4703-8e28-f9368df3d4aa', 'qcm', 'Qu est-ce que le harcelement scolaire ?', '{"bonne":1,"choix":["Une forme de jeu","Des actes repetes de violence ou moqueries envers un meme eleve","Une punition","Un sport"],"explication":"Le harcelement est des actes repetes d agression physique ou verbale envers un eleve."}', 'Des actes repetes de violence ou moqueries envers un meme eleve', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('978d0775-dd33-46cc-b5f0-6c06feaa434d', 'a9bb0f5f-ddb3-4703-8e28-f9368df3d4aa', 'qcm', 'Quel est le role du directeur dans une ecole ?', '{"bonne":1,"choix":["Enseigner toutes les matieres","Administrer et gerer l ecole, superviser les maitres et eleves","Surveiller la cantine","Reparer les batiments"],"explication":"Le directeur est le responsable administratif de l ecole, il gere le personnel et les eleves."}', 'Administrer et gerer l ecole, superviser les maitres et eleves', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('aaa99425-4a18-44fc-8324-1ca26cd84e39', 'a9bb0f5f-ddb3-4703-8e28-f9368df3d4aa', 'qcm', 'Que faire si tu es temoin de harcelement ?', '{"bonne":2,"choix":["Rire avec les harceleurs","Ne rien faire","En informer un adulte (maitre, directeur, parent)","Filmer et publier"],"explication":"Face au harcelement, on doit en avertir un adulte de confiance pour que cela cesse."}', 'En informer un adulte (maitre, directeur, parent)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c56d2508-ec31-4030-8a47-f76491db1393', 'a9bb0f5f-ddb3-4703-8e28-f9368df3d4aa', 'qcm', 'Que doit faire un eleve en retard ?', '{"bonne":2,"choix":["Rentrer chez lui","Entrer sans rien dire","S excuser aupres du maitre et s installer calmement","Attendre dehors toute la journee"],"explication":"Un eleve en retard doit s excuser poliment avant d entrer et de s installer."}', 'S excuser aupres du maitre et s installer calmement', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c60f4f88-b37a-4465-a182-08d2ef0ed67b', 'a9bb0f5f-ddb3-4703-8e28-f9368df3d4aa', 'qcm', 'Pourquoi faut-il aller a l ecole ?', '{"bonne":1,"choix":["Pour jouer avec les amis","Pour apprendre, s instruire et avoir un avenir meilleur","Parce que c est oblige seulement","Pour echapper a la maison"],"explication":"L ecole permet d apprendre, de se former et de se construire un avenir meilleur."}', 'Pour apprendre, s instruire et avoir un avenir meilleur', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('043ee808-4193-4fdb-b615-d108d946e9ed', 'aab39058-ec88-462a-9e86-5442e99aaeca', 'qcm', 'Combien de districts compte la Cote d Ivoire ?', '{"bonne":0,"choix":["12","14","31","33"],"explication":"La CI est divisee en 14 districts autonomes depuis la reforme administrative."}', '14', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('16a9a0f2-a14d-4ccc-afce-052c6216a894', 'aab39058-ec88-462a-9e86-5442e99aaeca', 'qcm', 'Quelle est la capitale politique de la Cote d Ivoire ?', '{"bonne":1,"choix":["Abidjan","Yamoussoukro","Bouake","San Pedro"],"explication":"Yamoussoukro est la capitale politique officielle de la CI depuis 1983."}', 'Yamoussoukro', 10) ON CONFLICT (id) DO NOTHING;
