INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('4bdd14a1-3260-46fd-b8b8-f03af646c76c', 'aab39058-ec88-462a-9e86-5442e99aaeca', 'qcm', 'Combien de pays frontaliers a la Cote d Ivoire ?', '{"bonne":2,"choix":["3","4","5","6"],"explication":"La CI a 5 pays voisins : Mali, Burkina Faso, Ghana, Liberia, Guinee."}', '5', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('5fa5aa04-818d-48a1-9f53-c774b2944465', 'aab39058-ec88-462a-9e86-5442e99aaeca', 'qcm', 'Quelle est la capitale economique de la Cote d Ivoire ?', '{"bonne":2,"choix":["Yamoussoukro","Bouake","Abidjan","Daloa"],"explication":"Abidjan est la capitale economique et la plus grande ville de Cote d Ivoire."}', 'Abidjan', 10) ON CONFLICT (id) DO NOTHING;
