INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('874c29de-821f-43d5-ad84-d3b0b9c70c73', 'c5cf9520-8082-4f8a-9677-b8f1716a8ad8', 'qcm', 'Qui etait Frederick Douglass ?', '{"bonne":1,"choix":["Un roi africain","Un esclave americain devenu militant abolitionniste","Un explorateur europeen","Un missionnaire"],"explication":"Frederick Douglass, ancien esclave, est devenu un grand militant pour l abolition de l esclavage aux USA."}', 'Un esclave americain devenu militant abolitionniste', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('91b451f9-4963-44e6-95ac-3007005561f3', 'c5cf9520-8082-4f8a-9677-b8f1716a8ad8', 'qcm', 'En quelle annee la France a-t-elle aboli l esclavage definitivement ?', '{"bonne":2,"choix":["1789","1815","1848","1900"],"explication":"La France a aboli definitivement l esclavage le 27 avril 1848 (2eme abolition)."}', '1848', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a2324662-0d90-4029-a694-75b67ce2f6cf', 'c5cf9520-8082-4f8a-9677-b8f1716a8ad8', 'qcm', 'Qu est-ce qu une "porte du non-retour" ?', '{"bonne":1,"choix":["Un monument de la victoire","La derniere porte franchie par les esclaves avant de s embarquer","Un symbole de liberte","Un fort colonial"],"explication":"La porte du non-retour (Ouidah, Benin) symbolise le point de depart des esclaves deportes."}', 'La derniere porte franchie par les esclaves avant de s embarquer', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c04bc961-4da6-49a5-a1e2-5162a076a2ba', 'c5cf9520-8082-4f8a-9677-b8f1716a8ad8', 'qcm', 'Quelles consequences la traite negriere a-t-elle eues sur l Afrique ?', '{"bonne":1,"choix":["Elle a enrichi l Afrique","Elle a depeupl les regions et desorganise les societes","Elle n a eu aucune consequence","Elle a favorise le developpement de l Afrique"],"explication":"La traite a depopule des regions entieres et destabilise les structures sociales africaines."}', 'Elle a depeupl les regions et desorganise les societes', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('20cd0ccb-dcbf-43a7-98c2-920cfd180006', 'c93d5c14-362f-4b42-87be-6bd999e79a82', 'qcm', 'Qu est-ce que le civisme environnemental ?', '{"bonne":1,"choix":["Planter beaucoup d arbres seulement","Respecter l environnement dans ses comportements quotidiens (ne pas polluer, economiser...)","Organiser des marches ecologiques","Aller en foret le week-end"],"explication":"Le civisme environnemental c est adopter au quotidien des comportements respectueux de la nature."}', 'Respecter l environnement dans ses comportements quotidiens (ne pas polluer, economiser...)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('343c7cde-623d-44f4-b1de-84a906d8410f', 'c93d5c14-362f-4b42-87be-6bd999e79a82', 'qcm', 'Pourquoi ne faut-il pas brener les ordures en ville ?', '{"bonne":1,"choix":["Parce que c est interdit seulement","Parce que la fumee des ordures brulee est toxique et pollue l air","Parce que ca fait du bruit","Parce que c est moche"],"explication":"La combustion des ordures degage des substances toxiques qui polluent l air et nuisent a la sante."}', 'Parce que la fumee des ordures brulee est toxique et pollue l air', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('54734002-9891-4e55-a6b2-67cdc30f58b5', 'c93d5c14-362f-4b42-87be-6bd999e79a82', 'qcm', 'Qu est-ce que la biodiversite ?', '{"bonne":1,"choix":["La diversite des langues","La variete des especes vivantes sur Terre","La diversite des mineraux","La variete des aliments"],"explication":"La biodiversite est la diversite de toutes les formes de vie sur Terre (plantes, animaux, champignons...)."}', 'La variete des especes vivantes sur Terre', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('704b07ae-3d0b-4d5e-9139-2bae4158cfe0', 'c93d5c14-362f-4b42-87be-6bd999e79a82', 'qcm', 'Qu est-ce qu une aire protegee ?', '{"bonne":1,"choix":["Un quartier securise","Une zone ou la nature est protegee par la loi contre les activites humaines nuisibles","Un parc de loisirs","Un terrain agricole"],"explication":"Une aire protegee (parc national, reserve) est une zone legalement protegee pour la biodiversite."}', 'Une zone ou la nature est protegee par la loi contre les activites humaines nuisibles', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('7eb56732-5c75-4e15-a7c4-20be9850a593', 'c93d5c14-362f-4b42-87be-6bd999e79a82', 'qcm', 'Comment planter un arbre contribue-t-il a l environnement ?', '{"bonne":1,"choix":["Cela ne change rien","Les arbres produisent de l oxygene, fixent le CO2, retiennent l eau et abritent les animaux","Cela embellit seulement","Cela attire les insectes nuisibles"],"explication":"Les arbres produisent de l oxygene, absorbent le CO2, retiennent le sol et abritent la faune."}', 'Les arbres produisent de l oxygene, fixent le CO2, retiennent l eau et abritent les animaux', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('82a294f8-62ab-4f87-991f-c9fcd8f7e797', 'c93d5c14-362f-4b42-87be-6bd999e79a82', 'qcm', 'Pourquoi est-il important de proteger les cours d eau ?', '{"bonne":1,"choix":["Pour les garder beaux","Les cours d eau sont essentiels a la vie, a l agriculture, a la peche et a l eau potable","Pour faire du tourisme","Pour les loisirs seulement"],"explication":"Les fleuves et lacs sont indispensables pour l eau potable, la peche, l agriculture et les ecosystemes."}', 'Les cours d eau sont essentiels a la vie, a l agriculture, a la peche et a l eau potable', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('8b255d06-3ca6-46ed-9abc-16faaacbfa3f', 'c93d5c14-362f-4b42-87be-6bd999e79a82', 'qcm', 'Qu est-ce que la journee de l environnement (5 juin) ?', '{"bonne":1,"choix":["La fete des forets","La journee mondiale de l environnement pour sensibiliser a la protection de la nature","Le debut de la saison des pluies","Une fete nationale africaine"],"explication":"Le 5 juin est la Journee Mondiale de l Environnement, instituee par l ONU en 1972."}', 'La journee mondiale de l environnement pour sensibiliser a la protection de la nature', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a90c25c2-39fe-4180-a86f-7dce5e8f8878', 'c93d5c14-362f-4b42-87be-6bd999e79a82', 'qcm', 'Que faire avec les emballages plastiques ?', '{"bonne":2,"choix":["Les jeter par terre","Les bruter","Les mettre a la poubelle ou les recycler","Les donner aux animaux"],"explication":"Les emballages plastiques doivent aller a la poubelle ou etre recycles, jamais dans la nature."}', 'Les mettre a la poubelle ou les recycler', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('b72ab22b-3627-470c-82f1-146691e83e57', 'c93d5c14-362f-4b42-87be-6bd999e79a82', 'qcm', 'Comment peut-on economiser l eau au quotidien ?', '{"bonne":2,"choix":["En laissant couler le robinet","En prenant des bains tres longs","En fermant le robinet quand on se brosse les dents, en recuperant l eau de pluie","En ne se lavant plus"],"explication":"Fermer le robinet inutilement et recuperer l eau de pluie sont de bonnes habitudes d economie d eau."}', 'En fermant le robinet quand on se brosse les dents, en recuperant l eau de pluie', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('fc78e2c3-7a3d-4aea-a7e0-8d2ed5417a00', 'c93d5c14-362f-4b42-87be-6bd999e79a82', 'qcm', 'Que faire si tu vois quelqu un jeter des ordures dans un espace public ?', '{"bonne":2,"choix":["Jeter aussi","Ne rien faire","Lui rappeler poliment qu il ne faut pas polluer ou en avertir un responsable","L insulter"],"explication":"Le civisme implique de rappeler poliment les regles ou d alerter les responsables en cas de pollution."}', 'Lui rappeler poliment qu il ne faut pas polluer ou en avertir un responsable', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('05340045-89dc-472c-83bd-cb990ea4473e', 'cc435767-a993-4675-9b1c-b62ad330f5b7', 'qcm', 'Quel est le pluriel de "un journal" ?', '{"bonne":1,"choix":["des journaus","des journaux","des journals","des journalx"],"explication":"-al → -aux au pluriel : journal → journaux"}', 'des journaux', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1fe71047-49ca-4067-a884-e982bac74e52', 'cc435767-a993-4675-9b1c-b62ad330f5b7', 'qcm', 'Quel est le pluriel de "le nez" ?', '{"bonne":1,"choix":["les nezs","les nez","les nezx","les nezaux"],"explication":"Les noms terminés par -s, -x, -z ne changent pas au pluriel : nez → nez"}', 'les nez', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('53751a73-fbef-43bd-91c3-62b74a892444', 'cc435767-a993-4675-9b1c-b62ad330f5b7', 'qcm', 'Quel est le pluriel général des noms en français ?', '{"bonne":2,"choix":["On ajoute -x","On ajoute -es","On ajoute -s","On ajoute -ent"],"explication":"La règle générale est d''ajouter -s : livre → livres"}', 'On ajoute -s', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('6a13e28b-1ea9-4791-b213-424172f57cb5', 'cc435767-a993-4675-9b1c-b62ad330f5b7', 'qcm', 'Quel est le pluriel de "un oiseau" ?', '{"bonne":0,"choix":["des oiseaux","des oiseau","des oiseaus","les oiseau"],"explication":"Les noms terminés par -eau font leur pluriel en -eaux : oiseau → oiseaux"}', 'des oiseaux', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('8bdb5ca1-4798-41fe-8fea-4d7358cacea6', 'cc435767-a993-4675-9b1c-b62ad330f5b7', 'qcm', 'Quel est le pluriel de "un cheval" ?', '{"bonne":1,"choix":["des chevals","des chevaux","des cheval","des chevales"],"explication":"Les noms en -al font leur pluriel en -aux : cheval → chevaux"}', 'des chevaux', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('9e660ddc-9bd9-4391-a994-e10d2f9fe0a1', 'cc435767-a993-4675-9b1c-b62ad330f5b7', 'qcm', 'Quel est le pluriel de "un pou" ?', '{"bonne":2,"choix":["des pous","des pouz","des poux","des pou"],"explication":"Quelques noms en -ou font leur pluriel en -oux : pou, bijou, genou, hibou..."}', 'des poux', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('b451c0e0-b658-4f5e-8257-1e7590911cb9', 'cc435767-a993-4675-9b1c-b62ad330f5b7', 'qcm', 'Quel pluriel est incorrect ?', '{"bonne":3,"choix":["des maisons","des arbres","des chevaux","des animaux"],"explication":"Tous sont corrects ! (animaux = pluriel de animal en -al)"}', 'des animaux', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('bbdd281e-c6d1-4ab9-8872-d18e9ebf4645', 'cc435767-a993-4675-9b1c-b62ad330f5b7', 'qcm', 'Quel est le pluriel de "un château" ?', '{"bonne":0,"choix":["des châteaux","des château","des châteaux","des châteaus"],"explication":"-eau → -eaux au pluriel : château → châteaux"}', 'des châteaux', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('bdb503b2-8090-4c14-856d-1c78227233c9', 'cc435767-a993-4675-9b1c-b62ad330f5b7', 'qcm', 'Quel est le pluriel de "un bal" ?', '{"bonne":0,"choix":["des bals","des baux","des balx","des ball"],"explication":"Exception : \"bal\" fait \"bals\" au pluriel (pas \"baux\")"}', 'des bals', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('dcad0037-850f-47b8-accd-a9d24ac254ed', 'cc435767-a993-4675-9b1c-b62ad330f5b7', 'qcm', 'Quel est le pluriel de "un pneu" ?', '{"bonne":0,"choix":["des pneus","des pneaux","des pneux","des pneumatiques"],"explication":"\"Pneu\" fait \"pneus\" au pluriel (exception, les noms en -eu prennent -x sauf quelques exceptions)"}', 'des pneus', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0ce65a1b-acac-4966-9206-b3cf17a50371', 'd04c6013-4965-4d6e-a09a-7099ade9959d', 'qcm', 'Quelle grande lagune est sur la frontiere CI-Ghana ?', '{"bonne":1,"choix":["La lagune Ebrié","La lagune Aby","La lagune Tendo","La lagune Ono"],"explication":"La lagune Aby (Assinie) est la deuxieme plus grande lagune de CI, pres de la frontiere ghanéenne."}', 'La lagune Aby', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('26e52694-a502-456d-99a7-b20db61f3d5d', 'd04c6013-4965-4d6e-a09a-7099ade9959d', 'qcm', 'Quelle est la capitale du Mali ?', '{"bonne":3,"choix":["Segou","Gao","Mopti","Bamako"],"explication":"Bamako est la capitale et la plus grande ville du Mali."}', 'Bamako', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('2b0eddd7-fe77-434b-b7ce-48b65ef1e71d', 'd04c6013-4965-4d6e-a09a-7099ade9959d', 'qcm', 'Quelle ville ouest-africaine est la capitale du Niger ?', '{"bonne":2,"choix":["Agadez","Zinder","Niamey","Tahoua"],"explication":"Niamey est la capitale du Niger."}', 'Niamey', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('330e0300-5d42-48c2-8c4b-c96df82a01c1', 'd04c6013-4965-4d6e-a09a-7099ade9959d', 'qcm', 'Quel peuple nomade vit dans le Sahel d Afrique de l Ouest ?', '{"bonne":1,"choix":["Les Yoruba","Les Touareg","Les Ashanti","Les Mossi"],"explication":"Les Touareg sont un peuple nomade berbere vivant dans le Sahara et le Sahel."}', 'Les Touareg', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('35be09ab-2469-44a3-9c85-ab90cf24ef34', 'd04c6013-4965-4d6e-a09a-7099ade9959d', 'qcm', 'Quel pays d Afrique de l Ouest est une ile dans l Atlantique ?', '{"bonne":1,"choix":["Le Senegal","Le Cap-Vert","La Gambie","La Guinee-Bissau"],"explication":"Le Cap-Vert est un archipel de 10 iles dans l ocean Atlantique, au large de la cote ouest-africaine."}', 'Le Cap-Vert', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('40f02d25-dc7f-4e11-a064-55f59f5ef5bd', 'd04c6013-4965-4d6e-a09a-7099ade9959d', 'qcm', 'Quelle est la monnaie commune a 8 pays d Afrique de l Ouest ?', '{"bonne":2,"choix":["Le dollar","Le naira","Le franc CFA","Le dinar"],"explication":"Le franc CFA (FCFA) est utilise par 8 pays de l UEMOA dont la CI, le Senegal, le Mali..."}', 'Le franc CFA', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('46eb6f2b-36fd-4611-a2ab-687ed9870ef6', 'd04c6013-4965-4d6e-a09a-7099ade9959d', 'qcm', 'Quel pays d Afrique de l Ouest est completement entoure par le Senegal (sauf la cote) ?', '{"bonne":1,"choix":["La Guinee-Bissau","La Gambie","La Mauritanie","La Guinee"],"explication":"La Gambie est un petit pays completement entoure par le Senegal, sauf sa cote atlantique."}', 'La Gambie', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('6cc00cec-0ee8-49c7-ae6a-e7f43558b85f', 'd04c6013-4965-4d6e-a09a-7099ade9959d', 'qcm', 'Quel fleuve traverse le Mali, le Niger et le Nigeria ?', '{"bonne":2,"choix":["Le Nil","La Volta","Le Niger","Le Senegal"],"explication":"Le Niger (4 180 km) est le fleuve le plus important d Afrique de l Ouest."}', 'Le Niger', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c98ec3ea-0a05-4f5a-838b-f8fec6017fb0', 'd04c6013-4965-4d6e-a09a-7099ade9959d', 'qcm', 'Quel est le plus grand pays d Afrique de l Ouest en superficie ?', '{"bonne":3,"choix":["Le Nigeria","Le Ghana","La Mauritanie","Le Mali"],"explication":"Le Mali est le plus grand pays d Afrique de l Ouest avec 1,24 million km2."}', 'Le Mali', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e87e0a31-0682-4364-a9d1-7f0cecda51a6', 'd04c6013-4965-4d6e-a09a-7099ade9959d', 'qcm', 'Combien de pays composent la CEDEAO ?', '{"bonne":2,"choix":["8","12","15","20"],"explication":"La CEDEAO (Communaute Economique des Etats de l Afrique de l Ouest) regroupe 15 pays."}', '15', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0c45957c-7b3b-4558-b3e2-4824615b9a7a', 'd07c0119-1541-4c8c-b588-e4f7dc484bb2', 'qcm', 'Quelle est la religion majoritaire en CI ?', '{"bonne":2,"choix":["Le christianisme uniquement","L islam uniquement","Islam et christianisme a parts quasi egales","Le bouddhisme"],"explication":"La CI a environ 42% de musulmans, 34% de chretiens et des religions traditionnelles."}', 'Islam et christianisme a parts quasi egales', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1ec092ea-5029-469c-98d2-9256bed4c0b8', 'd07c0119-1541-4c8c-b588-e4f7dc484bb2', 'qcm', 'Quelle est la population approximative de la CI ?', '{"bonne":2,"choix":["10 millions","17 millions","27 millions","35 millions"],"explication":"La CI compte environ 27 millions d habitants (recensement 2021)."}', '27 millions', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('5841b31b-b513-4407-a15f-d5b4f484b692', 'd07c0119-1541-4c8c-b588-e4f7dc484bb2', 'qcm', 'Que signifie l expression "pays de la lagune" pour la CI ?', '{"bonne":1,"choix":["Que la CI est un pays maritime sans lagunes","Que la CI a de nombreuses lagunes sur sa cote","Que la CI exporte du poisson","Que la CI a un lac"],"explication":"La cote ivoirienne est marquee par de nombreuses lagunes (Ebrié, Aby, Ono...)."}', 'Que la CI a de nombreuses lagunes sur sa cote', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('59c8acfc-e78c-416b-8043-cfdca191bf2a', 'd07c0119-1541-4c8c-b588-e4f7dc484bb2', 'qcm', 'Quelle ville est le principal centre commercial du nord de la CI ?', '{"bonne":2,"choix":["Man","Bouake","Korhogo","Odienne"],"explication":"Korhogo est la capitale du nord et un important centre commercial."}', 'Korhogo', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('5f240323-b957-4e48-8996-9aa80505f591', 'd07c0119-1541-4c8c-b588-e4f7dc484bb2', 'qcm', 'Quelle est la langue officielle de la CI ?', '{"bonne":2,"choix":["L anglais","Le dioula","Le francais","Le baoule"],"explication":"Le francais est la langue officielle de la Cote d Ivoire."}', 'Le francais', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a4c929e1-652e-4eda-9afd-a12a1167e349', 'd07c0119-1541-4c8c-b588-e4f7dc484bb2', 'qcm', 'Quel groupe ethnique est originaire du nord de la CI ?', '{"bonne":1,"choix":["Les Bete","Les Dioula (Mandingo)","Les Agni","Les Krou"],"explication":"Les Dioula (Mandingo ou Mande) sont principalement au nord de la CI."}', 'Les Dioula (Mandingo)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ad558544-a612-4c03-9412-c7e0bedd6823', 'd07c0119-1541-4c8c-b588-e4f7dc484bb2', 'qcm', 'Combien de langues sont parlees en CI ?', '{"bonne":2,"choix":["20","40","60 a 70","100"],"explication":"La CI compte environ 60 a 70 langues et dialectes differents."}', '60 a 70', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('b1cdb6a6-cd42-4516-a31c-39a96107f543', 'd07c0119-1541-4c8c-b588-e4f7dc484bb2', 'qcm', 'Quel est l animal embleme de la CI ?', '{"bonne":1,"choix":["Le lion","L elephant","La gazelle","Le leopard"],"explication":"L elephant est l animal embleme de la Cote d Ivoire, symbole de force et de sagesse."}', 'L elephant', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('b3ae2d77-680d-4914-8648-836b77f9dab2', 'd07c0119-1541-4c8c-b588-e4f7dc484bb2', 'qcm', 'Quel groupe ethnique est majoritaire a Abidjan ?', '{"bonne":1,"choix":["Uniquement les Baoule","Toutes les ethnies sont representees","Les Dioula seulement","Les Agni"],"explication":"Abidjan est une ville cosmopolite ou toutes les ethnies et nationalites cohabitent."}', 'Toutes les ethnies sont representees', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('fdc0fb35-1b5e-48af-8822-168f5564947e', 'd07c0119-1541-4c8c-b588-e4f7dc484bb2', 'qcm', 'A quel grand groupe appartient le peuple Baoule ?', '{"bonne":2,"choix":["Gur (Voltaique)","Krou","Akan","Mande"],"explication":"Les Baoule font partie du groupe Akan, comme les Agni et les Abron."}', 'Akan', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('103f22cf-db4e-4185-8c96-43cf399034b4', 'd2d0c3d2-5a94-4c0e-8322-fcee89f0fb39', 'qcm', 'Comment écrit-on "trois mille deux cent quarante-cinq" en chiffres ?', '{"bonne":0,"choix":["3 245","3 425","2 345","3 254"],"explication":"Trois mille = 3000, deux cent = 200, quarante-cinq = 45 → 3 245"}', '3 245', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('26382e38-9b51-4598-b940-7878362b60c2', 'd2d0c3d2-5a94-4c0e-8322-fcee89f0fb39', 'qcm', 'Quel est le plus grand nombre parmi 5 432, 5 342, 5 423, 5 243 ?', '{"bonne":2,"choix":["5 342","5 423","5 432","5 243"],"explication":"On compare chiffre par chiffre : les milliers sont égaux (5), les centaines 4>3, donc 5 432 est le plus grand"}', '5 432', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('2f6a2973-d19a-4170-9cc3-0b2de0f244bd', 'd2d0c3d2-5a94-4c0e-8322-fcee89f0fb39', 'qcm', 'Quel est le chiffre des centaines dans 4 756 ?', '{"bonne":1,"choix":["4","7","5","6"],"explication":"Dans 4756 : 4=milliers, 7=centaines, 5=dizaines, 6=unités"}', '7', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('5d938841-74c8-48cc-ab6d-01dafe297794', 'd2d0c3d2-5a94-4c0e-8322-fcee89f0fb39', 'qcm', 'Combien de centaines y a-t-il dans 1 000 ?', '{"bonne":1,"choix":["1","10","100","1 000"],"explication":"1 000 = 10 × 100, donc 10 centaines"}', '10', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a0cd124f-72b8-4543-a6fa-75158c253c71', 'd2d0c3d2-5a94-4c0e-8322-fcee89f0fb39', 'qcm', 'Range ces nombres du plus petit au plus grand : 2 050, 2 500, 2 005, 2 505', '{"bonne":0,"choix":["2 005, 2 050, 2 500, 2 505","2 050, 2 005, 2 500, 2 505","2 500, 2 505, 2 050, 2 005","2 005, 2 500, 2 050, 2 505"],"explication":"2 005 < 2 050 < 2 500 < 2 505"}', '2 005, 2 050, 2 500, 2 505', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c0d32e39-f5ec-48a3-b87e-077909b311e8', 'd2d0c3d2-5a94-4c0e-8322-fcee89f0fb39', 'qcm', 'Quel nombre vient juste avant 3 000 ?', '{"bonne":1,"choix":["3 001","2 999","2 990","2 900"],"explication":"3 000 - 1 = 2 999"}', '2 999', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ca7cdbb9-53da-435b-a7f6-6d34170e376b', 'd2d0c3d2-5a94-4c0e-8322-fcee89f0fb39', 'qcm', 'Quel nombre est la moitié de 8 000 ?', '{"bonne":1,"choix":["400","4 000","800","40"],"explication":"8 000 ÷ 2 = 4 000"}', '4 000', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('de9e19b1-2dc0-4187-a483-9d20b7b6ba44', 'd2d0c3d2-5a94-4c0e-8322-fcee89f0fb39', 'qcm', 'Écris en chiffres : huit mille soixante-dix', '{"bonne":1,"choix":["8 007","8 070","8 700","807"],"explication":"Huit mille = 8 000, soixante-dix = 70 → 8 070"}', '8 070', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e2134ba5-dc8c-436a-88e1-a87a439c459a', 'd2d0c3d2-5a94-4c0e-8322-fcee89f0fb39', 'qcm', 'Dans 7 084, combien y a-t-il de dizaines ?', '{"bonne":1,"choix":["70","8","0","7 084"],"explication":"Le chiffre des dizaines est 8. Il y a 8 dizaines (et 7 084 = 708 dizaines + 4 unités)"}', '8', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e4fa2f46-be45-4827-a5b8-499800d1cf7d', 'd2d0c3d2-5a94-4c0e-8322-fcee89f0fb39', 'qcm', 'Quelle est la valeur du chiffre 6 dans 6 391 ?', '{"bonne":3,"choix":["6","60","600","6 000"],"explication":"Le 6 est à la position des milliers : sa valeur est 6 000"}', '6 000', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0642f4ed-8652-493a-aae7-b1e023e14605', 'd63fe2af-b895-4d2b-9c76-7542ce7791e1', 'qcm', 'Combien de grammes y a-t-il dans 1 kg ?', '{"bonne":2,"choix":["100 g","500 g","1 000 g","10 000 g"],"explication":"1 kg = 1 000 g"}', '1 000 g', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('182a1f6c-740a-48a7-b4ae-13f741132330', 'd63fe2af-b895-4d2b-9c76-7542ce7791e1', 'qcm', 'Un sac pèse 5 kg 750 g. On retire 1 kg 200 g. Quelle est la masse restante ?', '{"bonne":1,"choix":["4 450 g","4 550 g","4 650 g","3 550 g"],"explication":"5 750 g - 1 200 g = 4 550 g"}', '4 550 g', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1d77c34b-afd7-4856-8ea7-a7dc52d76e7e', 'd63fe2af-b895-4d2b-9c76-7542ce7791e1', 'qcm', 'Convertis 2 750 g en kg et g', '{"bonne":0,"choix":["2 kg 750 g","27 kg 50 g","2 kg 075 g","275 kg"],"explication":"2 750 g = 2 000 g + 750 g = 2 kg 750 g"}', '2 kg 750 g', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1fecb1dd-1d5d-4355-8d89-cdbceac9d636', 'd63fe2af-b895-4d2b-9c76-7542ce7791e1', 'qcm', 'Combien de grammes pèse un bébé de 3 kg 800 g ?', '{"bonne":2,"choix":["380 g","3 080 g","3 800 g","38 000 g"],"explication":"3 kg = 3 000 g, 3 000 + 800 = 3 800 g"}', '3 800 g', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('72d53a25-9105-4dff-9db0-14102bbe8312', 'd63fe2af-b895-4d2b-9c76-7542ce7791e1', 'qcm', 'Combien de kg y a-t-il dans 1 tonne ?', '{"bonne":2,"choix":["10 kg","100 kg","1 000 kg","10 000 kg"],"explication":"1 tonne = 1 000 kg"}', '1 000 kg', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('7d1c3078-7518-43ed-ae80-89392f4fffb6', 'd63fe2af-b895-4d2b-9c76-7542ce7791e1', 'qcm', 'Un boucher vend 750 g de viande à 4 clients. Quelle masse au total ?', '{"bonne":1,"choix":["2 500 g","3 000 g","3 500 g","4 000 g"],"explication":"750 × 4 = 3 000 g = 3 kg"}', '3 000 g', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('82b21dc0-3bc8-436d-a6ad-31c7ff617910', 'd63fe2af-b895-4d2b-9c76-7542ce7791e1', 'qcm', 'Convertis 4 500 g en kg et g', '{"bonne":1,"choix":["45 kg","4 kg 500 g","4 kg 050 g","450 kg"],"explication":"4 500 g = 4 000 g + 500 g = 4 kg 500 g"}', '4 kg 500 g', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('9af5d090-ae4f-4fcb-9dc2-eb8a5e2695fb', 'd63fe2af-b895-4d2b-9c76-7542ce7791e1', 'qcm', 'Quelle est la masse la plus lourde : 2 kg ou 1 500 g ?', '{"bonne":1,"choix":["1 500 g","2 kg","Elles sont égales","Impossible à dire"],"explication":"2 kg = 2 000 g > 1 500 g, donc 2 kg est plus lourd"}', '2 kg', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c9a5d6c6-ffc9-485e-8a3b-3355ef5447b2', 'd63fe2af-b895-4d2b-9c76-7542ce7791e1', 'qcm', 'Maman achète 2 kg de tomates et 500 g de piment. Quelle est la masse totale ?', '{"bonne":1,"choix":["2 050 g","2 500 g","3 000 g","1 500 g"],"explication":"2 kg = 2 000 g, 2 000 + 500 = 2 500 g"}', '2 500 g', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d632c3be-a80b-4452-acb4-5f1b73a12c50', 'd63fe2af-b895-4d2b-9c76-7542ce7791e1', 'qcm', 'Convertis 3 kg 250 g en grammes', '{"bonne":1,"choix":["3 025 g","3 250 g","325 g","32 500 g"],"explication":"3 kg = 3 000 g, 3 000 + 250 = 3 250 g"}', '3 250 g', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0d9565a2-a0a7-4c41-b191-3f382bc456cd', 'd79702cf-e585-488c-9f9c-1aee89793014', 'qcm', 'Quel préfixe signifie "avant" ?', '{"bonne":2,"choix":["in-","re-","pré-","dé-"],"explication":"\"Pré-\" signifie avant : prénom (avant le nom), prévoir (voir avant)"}', 'pré-', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('4529f89f-37d1-49dd-afc1-90b99079fa45', 'd79702cf-e585-488c-9f9c-1aee89793014', 'qcm', 'Forme un nouveau mot avec le préfixe "dé-" et le mot "faire" :', '{"bonne":1,"choix":["refaire","défaire","surfaire","contrefaire"],"explication":"\"Dé-\" + faire = défaire (= l''action contraire de faire)"}', 'défaire', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('4b53196f-7ff2-44be-a3c6-8d0f89d6e2ce', 'd79702cf-e585-488c-9f9c-1aee89793014', 'qcm', 'Que forme le suffixe "-tion" dans "construction" ?', '{"bonne":2,"choix":["Un adjectif","Un verbe","Un nom commun","Un adverbe"],"explication":"\"-tion\" forme des noms communs : construction, direction, question..."}', 'Un nom commun', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('6182b4c1-0cbb-40c7-9a86-86a927e47859', 'd79702cf-e585-488c-9f9c-1aee89793014', 'qcm', 'Forme un adjectif avec le suffixe "-able" et le verbe "manger" :', '{"bonne":2,"choix":["mangeux","mangible","mangeable","mangé"],"explication":"\"Manger\" + \"-able\" = \"mangeable\" (= qu''on peut manger)"}', 'mangeable', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('65607ce7-72af-4e72-bbdd-100f0e3b156c', 'd79702cf-e585-488c-9f9c-1aee89793014', 'qcm', 'Que signifie le préfixe "in-" dans "invisible" ?', '{"bonne":2,"choix":["Très","Toujours","Ne pas, non","Encore"],"explication":"\"In-\" signifie \"ne pas\" : invisible = qu''on ne peut pas voir"}', 'Ne pas, non', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a9df624d-cfcb-4bc6-b7f9-0d7410436480', 'd79702cf-e585-488c-9f9c-1aee89793014', 'qcm', 'Quel suffixe forme un nom à partir du verbe "chanter" ?', '{"bonne":0,"choix":["chanteur","chantable","chantif","chanteur"],"explication":"\"Chant-eur\" : le suffixe \"-eur\" indique la personne qui fait l''action"}', 'chanteur', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d584c0be-27b0-4838-b9e9-70bb6b9fc2eb', 'd79702cf-e585-488c-9f9c-1aee89793014', 'qcm', 'Que signifie "sous-marin" ?', '{"bonne":1,"choix":["Au-dessus de la mer","Sous la mer","À côté de la mer","En dehors de la mer"],"explication":"\"Sous-\" indique en dessous : sous-marin = qui va sous la mer"}', 'Sous la mer', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e01f3f66-ebc7-4d27-a445-cd09562433fc', 'd79702cf-e585-488c-9f9c-1aee89793014', 'qcm', 'Quel est le suffixe dans "boulanger" ?', '{"bonne":3,"choix":["boul-","boulan-","boulang-","-er"],"explication":"\"-er\" est le suffixe qui indique le métier : boulanger, épicier..."}', '-er', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ea02d056-fbc0-4714-9e68-7c2fe629cb7f', 'd79702cf-e585-488c-9f9c-1aee89793014', 'qcm', 'Quel est le préfixe dans le mot "refaire" ?', '{"bonne":1,"choix":["-faire","re-","faire-","refai-"],"explication":"\"Re-\" est le préfixe de \"refaire\" (= faire à nouveau)"}', 're-', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('fd440b89-833d-4d0d-8484-47e52698d17d', 'd79702cf-e585-488c-9f9c-1aee89793014', 'qcm', 'Quel suffixe transforme un nom en adjectif dans "soleil → ensoleillé" ?', '{"bonne":0,"choix":["-é","-ment","-tion","-eur"],"explication":"\"-é\" transforme un nom en adjectif : soleil → ensoleillé"}', '-é', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('228eac3a-c1ca-4caa-9be6-a4f126e2c33b', 'db489c17-5d81-4ac4-b4cd-78b1b569b79a', 'qcm', 'Qu est-ce qui provoque le paludisme ?', '{"bonne":2,"choix":["Un virus","Une bacterie","Un parasite transmis par un moustique","Le froid"],"explication":"Le paludisme est cause par un parasite transmis par le moustique anophele."}', 'Un parasite transmis par un moustique', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('30752703-8dec-4600-9368-c01b7a62f000', 'db489c17-5d81-4ac4-b4cd-78b1b569b79a', 'qcm', 'Combien de fois par jour faut-il se brosser les dents ?', '{"bonne":1,"choix":["1 fois","2 fois","3 fois","4 fois"],"explication":"Il faut se brosser les dents au moins 2 fois par jour : matin et soir."}', '2 fois', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('8389e77e-9828-4eda-b28d-f0a302626692', 'db489c17-5d81-4ac4-b4cd-78b1b569b79a', 'qcm', 'Qu est-ce qu un vaccin ?', '{"bonne":1,"choix":["Un medicament contre la douleur","Un produit qui protege contre certaines maladies","Un sirop pour la toux","Un remede traditionnel"],"explication":"Le vaccin renforce les defenses de l organisme contre certaines maladies."}', 'Un produit qui protege contre certaines maladies', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('97acf1ec-1826-4baf-b070-cd0f471f23a0', 'db489c17-5d81-4ac4-b4cd-78b1b569b79a', 'qcm', 'Pourquoi faut-il se laver les mains avec du savon ?', '{"bonne":1,"choix":["Pour sentir bon","Pour tuer les microbes","Pour avoir les mains douces","Pour economiser l eau"],"explication":"Le savon detruit les microbes et bacteries presentes sur les mains."}', 'Pour tuer les microbes', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a5733e4e-639b-4c02-95f8-82179b429b76', 'db489c17-5d81-4ac4-b4cd-78b1b569b79a', 'qcm', 'Qu est-ce que la diarrhee ?', '{"bonne":1,"choix":["Une maladie des yeux","Des selles trop frequentes et liquides","Une douleur des dents","Une fievre forte"],"explication":"La diarrhee se caracterise par des selles frequentes et liquides."}', 'Des selles trop frequentes et liquides', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c0943088-d434-4787-8ba0-39d3431d26ea', 'db489c17-5d81-4ac4-b4cd-78b1b569b79a', 'qcm', 'Comment se proteger du paludisme ?', '{"bonne":1,"choix":["Porter des habits chauds","Utiliser une moustiquaire","Boire beaucoup d eau","Manger des fruits"],"explication":"La moustiquaire impregnee protege efficacement contre les moustiques."}', 'Utiliser une moustiquaire', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c54c94f0-e6c5-4bf4-a317-3eec79b59879', 'db489c17-5d81-4ac4-b4cd-78b1b569b79a', 'qcm', 'Quelle eau peut-on boire sans risque ?', '{"bonne":2,"choix":["Eau de pluie","Eau de riviere","Eau traitee ou bouillie","Eau de mare"],"explication":"L eau traitee ou bouillie est sure pour la consommation."}', 'Eau traitee ou bouillie', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('df36fe92-353f-46e8-815f-248a24e78dc8', 'db489c17-5d81-4ac4-b4cd-78b1b569b79a', 'qcm', 'Combien d heures de sommeil un enfant de CE2 doit-il avoir ?', '{"bonne":2,"choix":["6 heures","8 heures","10 heures","12 heures"],"explication":"Un enfant a besoin de 10 heures de sommeil par nuit."}', '10 heures', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ef777568-012d-4c6a-b1e5-e339498f10f6', 'db489c17-5d81-4ac4-b4cd-78b1b569b79a', 'qcm', 'A quel moment faut-il absolument se laver les mains ?', '{"bonne":2,"choix":["Avant de manger","Apres les toilettes","Les deux reponses","Jamais"],"explication":"Il faut se laver les mains avant de manger et apres les toilettes."}', 'Les deux reponses', 10) ON CONFLICT (id) DO NOTHING;
