INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('10801cf9-b838-45d4-a22d-d2df8ffaeebd', 'e2e8f861-8ea8-49a4-ac0d-c5c5d9038ff2', 'qcm', 'Qu est-ce que l empathie ?', '{"bonne":1,"choix":["L egoisme","La capacite a comprendre et partager les sentiments des autres","La timidite","La curiosite"],"explication":"L empathie est la capacite de se mettre a la place de l autre et de comprendre ses emotions."}', 'La capacite a comprendre et partager les sentiments des autres', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('3b845fc6-0616-471b-97ba-f663bae97626', 'e2e8f861-8ea8-49a4-ac0d-c5c5d9038ff2', 'qcm', 'Qu est-ce que le racisme ?', '{"bonne":1,"choix":["Une opinion politique","Discriminer ou mepriser une personne a cause de son origine ou sa couleur","Un sport","Une forme de politesse"],"explication":"Le racisme est la discrimination envers des personnes a cause de leur origine ou couleur de peau."}', 'Discriminer ou mepriser une personne a cause de son origine ou sa couleur', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('73faef74-ffd3-49a4-999a-25c10e6c229e', 'e2e8f861-8ea8-49a4-ac0d-c5c5d9038ff2', 'qcm', 'Qu est-ce que la xenophobie ?', '{"bonne":1,"choix":["L amour des etrangers","Le rejet ou la haine des etrangers","La peur des animaux","L etude des cultures etrangeres"],"explication":"La xenophobie est le rejet ou la haine des etrangers ou de ce qui vient de l etranger."}', 'Le rejet ou la haine des etrangers', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('89438b6e-618d-40b3-8447-80c970ef55c8', 'e2e8f861-8ea8-49a4-ac0d-c5c5d9038ff2', 'qcm', 'Que signifie "la paix est le bien le plus precieux" ?', '{"bonne":1,"choix":["La paix est chere a acheter","Sans la paix, rien de bon n est possible (education, developpement, bonheur)","La paix est rare","La paix est un luxe"],"explication":"La paix est la condition essentielle du developpement, de l education et du bonheur collectif."}', 'Sans la paix, rien de bon n est possible (education, developpement, bonheur)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('8d9f60cc-5af4-4541-91cc-3e3b9173a092', 'e2e8f861-8ea8-49a4-ac0d-c5c5d9038ff2', 'qcm', 'Qu est-ce que la tolerance ?', '{"bonne":1,"choix":["Tout accepter sans reagir","Respecter les differences des autres et leurs opinions","Ignorer les problemes","Etre d accord avec tout le monde"],"explication":"La tolerance est le respect des differences : d opinion, de religion, d origine, de culture."}', 'Respecter les differences des autres et leurs opinions', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('9395d16f-3612-4afa-9b8b-9621675bc79e', 'e2e8f861-8ea8-49a4-ac0d-c5c5d9038ff2', 'qcm', 'Pourquoi faut-il respecter les personnes handicapees ?', '{"bonne":1,"choix":["Par pitie","Parce que ce sont des etres humains avec les memes droits et la meme dignite","Parce que la loi l oblige","Parce qu elles sont differentes"],"explication":"Les personnes handicapees ont exactement les memes droits et la meme dignite que tout le monde."}', 'Parce que ce sont des etres humains avec les memes droits et la meme dignite', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('a7247f8b-3bc6-4e61-acea-2f14f694773e', 'e2e8f861-8ea8-49a4-ac0d-c5c5d9038ff2', 'qcm', 'Comment resoudre un conflit entre camarades ?', '{"bonne":2,"choix":["Se battre pour gagner","Appeler ses grands freres","Dialoguer calmement et chercher un compromis","Fuir le probleme"],"explication":"Le dialogue calme et la recherche de compromis sont les meilleurs moyens de resoudre un conflit."}', 'Dialoguer calmement et chercher un compromis', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('b37e3412-6bb0-4d38-836d-402cf0986617', 'e2e8f861-8ea8-49a4-ac0d-c5c5d9038ff2', 'qcm', 'Que faire si quelqu un est victime d injustice autour de toi ?', '{"bonne":2,"choix":["Rire","Ne rien faire","Temoigner et en parler a un adulte responsable","S en aller"],"explication":"Face a l injustice, un bon citoyen ne reste pas indifferent : il temoigne et alerte les autorites."}', 'Temoigner et en parler a un adulte responsable', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e8816af8-f13c-4dee-ba0f-94beee4ef7fd', 'e2e8f861-8ea8-49a4-ac0d-c5c5d9038ff2', 'qcm', 'Comment la CI gere-t-elle sa diversite culturelle ?', '{"bonne":1,"choix":["En imposant une seule culture","En reconnaissant et valorisant les cultures des differentes ethnies","En interdisant les langues locales","En expulsant les minorites"],"explication":"La CI valorise sa diversite avec la devise \"Union-Discipline-Travail\" et des fetes culturelles."}', 'En reconnaissant et valorisant les cultures des differentes ethnies', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e943a161-1008-41d3-82e2-be5b13a2517b', 'e2e8f861-8ea8-49a4-ac0d-c5c5d9038ff2', 'qcm', 'Que signifie "vivre-ensemble" en CI ?', '{"bonne":1,"choix":["Habiter dans le meme immeuble","Coexister pacifiquement malgre les differences ethniques, religieuses, culturelles","Avoir les memes habitudes","Parler la meme langue"],"explication":"Le vivre-ensemble est la capacite a cohabiter pacifiquement malgre les differences."}', 'Coexister pacifiquement malgre les differences ethniques, religieuses, culturelles', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('01c8fdf8-10fa-4468-a26e-2efe708296c9', 'e45a2464-10f6-4585-b061-c564bd7e087e', 'qcm', 'Dans une liste, quel signe sépare les éléments ?', '{"bonne":2,"choix":["Le point","Le point d''interrogation","La virgule","Les deux-points"],"explication":"La virgule sépare les éléments d''une liste : \"J''achète du pain, du lait et du sucre.\""}', 'La virgule', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('04a79a3c-dd29-436c-9e79-012ee16d1d60', 'e45a2464-10f6-4585-b061-c564bd7e087e', 'qcm', 'Quel signe met-on à la fin d''un ordre (phrase impérative) ?', '{"bonne":2,"choix":[".","?","!",","],"explication":"Un ordre se termine souvent par un point d''exclamation : \"Viens !\""}', '!', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('3df1e5b4-0b05-44a1-bfa6-3d7bff818791', 'e45a2464-10f6-4585-b061-c564bd7e087e', 'qcm', 'À quoi sert la virgule ?', '{"bonne":2,"choix":["Terminer une phrase","Poser une question","Séparer des éléments dans une liste","Exprimer la surprise"],"explication":"La virgule sépare les éléments d''une liste ou des propositions."}', 'Séparer des éléments dans une liste', 10) ON CONFLICT (id) DO NOTHING;
