INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0e373ff0-a998-471e-84d3-e48caa655074', 'e488dc41-95e7-4a09-9c36-0bd7c81d0f9f', 'qcm', 'Quelles sont les couleurs de l arc-en-ciel ?', '{"bonne":1,"choix":["Rouge, vert, bleu","Rouge, orange, jaune, vert, bleu, indigo, violet","Noir, blanc, gris","Rouge, bleu, jaune"],"explication":"L arc-en-ciel est compose de 7 couleurs : rouge, orange, jaune, vert, bleu, indigo, violet."}', 'Rouge, orange, jaune, vert, bleu, indigo, violet', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1a8ae6f0-a401-4b65-8f43-f82503cd9e54', 'e488dc41-95e7-4a09-9c36-0bd7c81d0f9f', 'qcm', 'Comment se propage la lumiere ?', '{"bonne":1,"choix":["En courbe","En ligne droite","En zigzag","En cercles"],"explication":"La lumiere se propage en ligne droite (rayons lumineux)."}', 'En ligne droite', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('1e8487db-c705-4f0c-8193-fb975684fbfe', 'e488dc41-95e7-4a09-9c36-0bd7c81d0f9f', 'qcm', 'Pourquoi l ombre est-elle plus grande le matin que le midi ?', '{"bonne":1,"choix":["Parce qu il fait plus froid","Parce que le soleil est bas sur l horizon","Parce que l air est plus dense","Pour aucune raison"],"explication":"Le matin, le soleil est bas, ses rayons sont obliques et creent de longues ombres."}', 'Parce que le soleil est bas sur l horizon', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('29f2c13b-1966-4c2d-b5ef-c5d315d42772', 'e488dc41-95e7-4a09-9c36-0bd7c81d0f9f', 'qcm', 'Pourquoi voit-on les couleurs des objets ?', '{"bonne":1,"choix":["Parce que les objets emettent de la lumiere","Parce que les objets reflechissent certaines longueurs d onde de la lumiere","Parce que nos yeux produisent de la lumiere","Parce que l air colore les objets"],"explication":"Les objets absorbent certaines couleurs et reflechissent d autres vers nos yeux."}', 'Parce que les objets reflechissent certaines longueurs d onde de la lumiere', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('406cbb45-59b0-4b89-943a-632450c01496', 'e488dc41-95e7-4a09-9c36-0bd7c81d0f9f', 'qcm', 'Quelle est la source de lumiere naturelle la plus importante ?', '{"bonne":2,"choix":["La lune","Les etoiles","Le soleil","Le feu"],"explication":"Le soleil est notre principale source de lumiere naturelle."}', 'Le soleil', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('439ea96c-daf8-4c43-9619-966fd8acb6f6', 'e488dc41-95e7-4a09-9c36-0bd7c81d0f9f', 'qcm', 'Comment appelle-t-on un objet qui ne laisse pas passer la lumiere ?', '{"bonne":2,"choix":["Transparent","Translucide","Opaque","Brillant"],"explication":"Un objet opaque bloque completement la lumiere et cree une ombre."}', 'Opaque', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ce093b67-4d00-4089-83e2-b6055120fb3a', 'e488dc41-95e7-4a09-9c36-0bd7c81d0f9f', 'qcm', 'Qu est-ce qu une ombre ?', '{"bonne":1,"choix":["Un reflet de lumiere","La zone de manque de lumiere derriere un objet opaque","Une couleur sombre","Un type de nuage"],"explication":"L ombre se forme quand un objet opaque bloque les rayons lumineux."}', 'La zone de manque de lumiere derriere un objet opaque', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('da6310cc-a690-4291-8382-ceba3d170ead', 'e488dc41-95e7-4a09-9c36-0bd7c81d0f9f', 'qcm', 'A quelle vitesse se deplace la lumiere ?', '{"bonne":1,"choix":["300 km/s","300 000 km/s","30 000 km/s","3 000 000 km/s"],"explication":"La lumiere se deplace a environ 300 000 km par seconde dans le vide."}', '300 000 km/s', 10) ON CONFLICT (id) DO NOTHING;
