INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f500734a-67b8-4654-9436-3facc9aff2c6', 'e488dc41-95e7-4a09-9c36-0bd7c81d0f9f', 'qcm', 'Un objet transparent laisse-t-il passer la lumiere ?', '{"bonne":1,"choix":["Non","Oui, completement","Partiellement","Seulement la nuit"],"explication":"Un objet transparent laisse passer toute la lumiere (comme le verre clair)."}', 'Oui, completement', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('16476ad3-60db-4820-9e2a-332f935410b1', 'eca9d1a5-da0c-49bd-b745-aee4c595cc18', 'qcm', 'Qu est-ce qu une poulie ?', '{"bonne":1,"choix":["Un type de vis","Une roue avec une gorge permettant de guider une corde","Un type de marteau","Un plan incline"],"explication":"Une poulie est une roue avec une rainure dans laquelle passe une corde ou courroie."}', 'Une roue avec une gorge permettant de guider une corde', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('2c971db4-77b2-40f7-b71b-fca55c092907', 'eca9d1a5-da0c-49bd-b745-aee4c595cc18', 'qcm', 'Pourquoi un objet flotte-t-il sur l eau ?', '{"bonne":1,"choix":["Parce qu il est leger","Parce que la poussee d Archimede est superieure a son poids","Parce qu il contient de l air","Toutes ces reponses"],"explication":"Un objet flotte quand la poussee d Archimede (force de l eau vers le haut) est >= a son poids."}', 'Parce que la poussee d Archimede est superieure a son poids', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('3b981cce-d37e-41c4-bb68-d4ea89e8cd02', 'eca9d1a5-da0c-49bd-b745-aee4c595cc18', 'qcm', 'Pourquoi une bille roule-t-elle plus loin sur un sol lisse que sur du sable ?', '{"bonne":1,"choix":["Parce que le sol lisse est plus dur","Parce qu il y a moins de frottement sur le sol lisse","Parce que le sable est lourd","Parce que la bille rebondit sur le lisse"],"explication":"Le sol lisse offre moins de frottement, donc la bille peut rouler plus loin."}', 'Parce qu il y a moins de frottement sur le sol lisse', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('431e5283-62c3-43ad-b5bf-f4651ace24a9', 'eca9d1a5-da0c-49bd-b745-aee4c595cc18', 'qcm', 'Qu est-ce que le frottement ?', '{"bonne":1,"choix":["Une force qui accelere le mouvement","Une force qui s oppose au mouvement entre deux surfaces en contact","Un type de levier","Une forme d energie"],"explication":"Le frottement est la force resistante qui s oppose au glissement entre deux surfaces."}', 'Une force qui s oppose au mouvement entre deux surfaces en contact', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('656ffe29-d2f5-4081-82b3-71f74624af9c', 'eca9d1a5-da0c-49bd-b745-aee4c595cc18', 'qcm', 'Quel est un exemple de levier de la vie courante ?', '{"bonne":1,"choix":["Une roue de velo","Les ciseaux","Un marteau (seul)","Un clou"],"explication":"Les ciseaux sont deux leviers croises fonctionnant autour d un pivot central."}', 'Les ciseaux', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('65ac1cd4-e210-41a0-96da-9f48ce2dc3f9', 'eca9d1a5-da0c-49bd-b745-aee4c595cc18', 'qcm', 'Qu est-ce qu une force ?', '{"bonne":1,"choix":["Un bruit fort","Une action qui peut mettre en mouvement, arreter ou deformer un objet","Une lumiere intense","Un courant electrique"],"explication":"Une force est une action mecanique qui peut modifier le mouvement ou la forme d un objet."}', 'Une action qui peut mettre en mouvement, arreter ou deformer un objet', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('66935a53-7c5c-4a5f-9c7f-a3fe8af54b71', 'eca9d1a5-da0c-49bd-b745-aee4c595cc18', 'qcm', 'Qu est-ce qu un levier ?', '{"bonne":1,"choix":["Un type de poulie","Une barre rigide qui pivote autour d un point d appui","Un engrenage","Un plan incline"],"explication":"Le levier est une machine simple consistant en une barre qui pivote sur un point d appui (fulcrum)."}', 'Une barre rigide qui pivote autour d un point d appui', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('6a429a23-749c-4b5c-90e9-c402956e72e2', 'eca9d1a5-da0c-49bd-b745-aee4c595cc18', 'qcm', 'Qu est-ce qu un aimant ?', '{"bonne":1,"choix":["Un conducteur electrique","Un objet qui attire le fer et d autres metaux","Un type de levier","Un objet transparent"],"explication":"Un aimant est un materiau qui exerce une force magnetique, attirant le fer et certains metaux."}', 'Un objet qui attire le fer et d autres metaux', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('90e335f9-cbf5-4fb8-b20d-b7b9307c625a', 'eca9d1a5-da0c-49bd-b745-aee4c595cc18', 'qcm', 'Qu est-ce qu un plan incline ?', '{"bonne":1,"choix":["Un levier horizontal","Une surface en pente utilisee pour soulever des charges","Un type de poulie","Une force verticale"],"explication":"Le plan incline est une surface en pente qui permet de soulever des charges avec moins de force."}', 'Une surface en pente utilisee pour soulever des charges', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f9576d4c-edbb-485e-98b7-d71185482129', 'eca9d1a5-da0c-49bd-b745-aee4c595cc18', 'qcm', 'Qu est-ce que la pesanteur (gravite) ?', '{"bonne":1,"choix":["Une force qui repousse les objets","La force qui attire les objets vers le centre de la Terre","Une force electrique","Une force magnetique"],"explication":"La gravite (pesanteur) est la force qui attire tous les objets vers le centre de la Terre."}', 'La force qui attire les objets vers le centre de la Terre', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('2540e324-189d-4e51-83d5-9a21bed682c5', 'f4d818f3-dd7e-492a-adba-fc1675f26732', 'qcm', 'Quel organisme international lutte pour la sante mondiale ?', '{"bonne":2,"choix":["L UNICEF","L UNESCO","L OMS (Organisation Mondiale de la Sante)","La Croix-Rouge seulement"],"explication":"L OMS est l agence de l ONU chargee de diriger et coordonner la sante publique mondiale."}', 'L OMS (Organisation Mondiale de la Sante)', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('7d1e43bb-a965-4b54-8765-ba568f8692b5', 'f4d818f3-dd7e-492a-adba-fc1675f26732', 'qcm', 'Qu est-ce qu une campagne de vaccination ?', '{"bonne":1,"choix":["Un programme de sport","Une operation pour vacciner un grand nombre de personnes contre une maladie","Un programme d alimentation","Une campagne publicitaire"],"explication":"Les campagnes de vaccination permettent d immuniser collectivement la population contre des maladies."}', 'Une operation pour vacciner un grand nombre de personnes contre une maladie', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('862a12fa-335f-416b-bdde-be87ecf97ccc', 'f4d818f3-dd7e-492a-adba-fc1675f26732', 'qcm', 'Qu est-ce que la Prevention Routine dans les centres de sante CI ?', '{"bonne":1,"choix":["Un type de medecine traditionnelle","Les consultations regulieres et vaccinations pour eviter les maladies avant qu elles surviennent","Les soins d urgence","Les medicaments gratuits"],"explication":"La prevention consiste a eviter les maladies par des vaccinations, consultations et bonnes habitudes."}', 'Les consultations regulieres et vaccinations pour eviter les maladies avant qu elles surviennent', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('8730206f-64a5-4b71-8006-d92a79beae13', 'f4d818f3-dd7e-492a-adba-fc1675f26732', 'qcm', 'Qu est-ce que la sante publique ?', '{"bonne":1,"choix":["La sante des fonctionnaires","L ensemble des actions pour proteger et ameliorer la sante de toute la population","La sante dans les hopitaux prives","La sante des sportifs"],"explication":"La sante publique vise a prevenir les maladies et ameliorer la sante de l ensemble de la population."}', 'L ensemble des actions pour proteger et ameliorer la sante de toute la population', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c28dfb2f-5a7a-4096-bd3a-ea81ee1ae231', 'f4d818f3-dd7e-492a-adba-fc1675f26732', 'qcm', 'Qu est-ce que la mutuelle de sante ?', '{"bonne":1,"choix":["Un hopital public","Un systeme d assurance collective sante ou les membres cotisent pour se soutenir","Une pharmacie","Un dispensaire gouvernemental"],"explication":"La mutuelle de sante est une solidarite financiere entre membres pour couvrir les frais medicaux."}', 'Un systeme d assurance collective sante ou les membres cotisent pour se soutenir', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('c5e5aae5-6bba-4069-b86a-72cf923f4a65', 'f4d818f3-dd7e-492a-adba-fc1675f26732', 'qcm', 'Pourquoi la qualite de l eau est-elle un probleme de sante publique ?', '{"bonne":1,"choix":["Parce que l eau a un gout","L eau contaminee provoque des maladies comme le cholera, la dysenterie, la typhoide...","Parce que l eau chere est toujours pure","Pour aucune raison"],"explication":"L eau contaminee est la source de nombreuses maladies mortelles, notamment dans les pays en developpement."}', 'L eau contaminee provoque des maladies comme le cholera, la dysenterie, la typhoide...', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d2931b28-eb8a-4106-88d9-c609d7080298', 'f4d818f3-dd7e-492a-adba-fc1675f26732', 'qcm', 'Qu est-ce que la malnutrition ?', '{"bonne":1,"choix":["Manger trop","Un etat de sante cause par un manque ou un exces de nutriments essentiels","Une forme d obsite","Manger des aliments locaux"],"explication":"La malnutrition survient quand l alimentation ne fournit pas les nutriments necessaires a la sante."}', 'Un etat de sante cause par un manque ou un exces de nutriments essentiels', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e19b835b-2ae2-41c1-942f-f346675eaf6d', 'f4d818f3-dd7e-492a-adba-fc1675f26732', 'qcm', 'Que faire en cas d epideamie dans le quartier ?', '{"bonne":1,"choix":["Ne rien changer","Suivre les conseils des autorites sanitaires, se faire soigner, respecter les mesures d hygiene","Quitter le pays","Ignorer les informations"],"explication":"En cas d epidemie, il faut respecter les consignes des autorites sanitaires pour se proteger et proteger les autres."}', 'Suivre les conseils des autorites sanitaires, se faire soigner, respecter les mesures d hygiene', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('f219e748-e241-4f75-a9b6-7a98bdf1db89', 'f4d818f3-dd7e-492a-adba-fc1675f26732', 'qcm', 'Pourquoi les latrines (toilettes) sont-elles importantes pour la sante publique ?', '{"bonne":1,"choix":["Pour le confort seulement","Elles evitent la contamination du sol et de l eau par les excreta, sources de maladies","Parce qu elles sont jolies","Pour economiser l eau"],"explication":"Les latrines empechent la contamination de l environnement par les dejections, source de nombreuses maladies."}', 'Elles evitent la contamination du sol et de l eau par les excreta, sources de maladies', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('fcb944cb-7ac4-4b51-8a33-e947818c8910', 'f4d818f3-dd7e-492a-adba-fc1675f26732', 'qcm', 'Comment le cholera se transmet-il ?', '{"bonne":2,"choix":["Par les moustiques","Par l air","Par l eau et les aliments contamines","Par le contact physique direct"],"explication":"Le cholera se transmet par l eau ou la nourriture contaminee par la bacterie Vibrio cholerae."}', 'Par l eau et les aliments contamines', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('0e42efad-6e02-43fb-8b75-8ac9cdf50829', 'f598139f-a958-4ffb-b9a7-52b4fcedfe5b', 'qcm', 'Accorde correctement : "une petite (fille)"', '{"bonne":1,"choix":["un petit fille","une petite fille","un petite fille","une petit fille"],"explication":"\"Fille\" est féminin singulier → \"une petite fille\""}', 'une petite fille', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('23e17f9d-f2fb-4efa-bb22-69ea48f9efd5', 'f598139f-a958-4ffb-b9a7-52b4fcedfe5b', 'qcm', 'Accorde : "Ils sont ___" (fatigué)', '{"bonne":2,"choix":["fatigué","fatiguée","fatigués","fatiguées"],"explication":"\"Ils\" = masculin pluriel → \"fatigués\" (adjectif attribut)"}', 'fatigués', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('2c51f59d-530d-4f87-9378-9bea36503f1b', 'f598139f-a958-4ffb-b9a7-52b4fcedfe5b', 'qcm', 'Quel accord est correct ?', '{"bonne":1,"choix":["des belle fleurs","des belles fleurs","des beaux fleurs","de belles fleur"],"explication":"\"Fleurs\" est féminin pluriel → \"des belles fleurs\""}', 'des belles fleurs', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('5ecb5edd-bc1a-408c-80ce-71d08b809a6f', 'f598139f-a958-4ffb-b9a7-52b4fcedfe5b', 'qcm', 'Accorde correctement : "___ grands arbres"', '{"bonne":2,"choix":["le grand arbre","un grand arbre","les grands arbres","la grande arbre"],"explication":"\"Arbres\" est masculin pluriel → \"les grands arbres\""}', 'les grands arbres', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('6ca4e006-e009-4409-89ba-6f375aaf08a0', 'f598139f-a958-4ffb-b9a7-52b4fcedfe5b', 'qcm', 'Quel est le pluriel de "un beau dessin" ?', '{"bonne":2,"choix":["un beaux dessin","des beaux dessins","de beaux dessins","des beaux dessin"],"explication":"\"De beaux dessins\" (pluriel : \"des\" → \"de\" devant adjectif, \"beau\" → \"beaux\")"}', 'de beaux dessins', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('b0f75365-9d36-4884-9ee0-826352b037fb', 'f598139f-a958-4ffb-b9a7-52b4fcedfe5b', 'qcm', 'Quel groupe nominal est correctement accordé ?', '{"bonne":1,"choix":["un vieux homme","un vieil homme","une vieux homme","un vieux hommes"],"explication":"\"Vieil\" est la forme de \"vieux\" devant un nom masculin singulier commençant par une voyelle."}', 'un vieil homme', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('cad16a78-ca65-49c5-9943-f102c626a43f', 'f598139f-a958-4ffb-b9a7-52b4fcedfe5b', 'qcm', 'Accorde : "les filles sont ___" (heureux)', '{"bonne":1,"choix":["heureux","heureuses","heureuse","heureux"],"explication":"\"Filles\" = féminin pluriel → \"heureuses\""}', 'heureuses', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('d7b277e4-4ce3-40e9-a47a-2f1ae2bbdfad', 'f598139f-a958-4ffb-b9a7-52b4fcedfe5b', 'qcm', 'Accorde l''adjectif : "La mangue est ___" (bon)', '{"bonne":2,"choix":["bon","bons","bonne","bonnes"],"explication":"\"Mangue\" est féminin singulier → \"bonne\""}', 'bonne', 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('e70e5d60-111a-4246-83eb-28dace7baffd', 'f598139f-a958-4ffb-b9a7-52b4fcedfe5b', 'qcm', 'Quel accord est incorrect ?', '{"bonne":1,"choix":["les bons élèves","les bonnes élèves","les belles fleurs","les petits enfants"],"explication":"\"Élèves\" ici est masculin pluriel → \"les bons élèves\", pas \"bonnes\""}', 'les bonnes élèves', 15) ON CONFLICT (id) DO NOTHING;
INSERT INTO exercice (id, lecon_id, type, enonce, options, bonne_reponse, points) VALUES ('ee23b992-795e-4153-bc48-aebffb874126', 'f598139f-a958-4ffb-b9a7-52b4fcedfe5b', 'qcm', 'Accorde : "une grande ___ (maison)"', '{"bonne":2,"choix":["grandes maisons","grand maison","grande maison","grands maisons"],"explication":"\"Maison\" est féminin singulier → \"grande maison\""}', 'grande maison', 10) ON CONFLICT (id) DO NOTHING;
